-- V20: Seed EN translations juz21_25

INSERT INTO mst_translation (ayah_id, language_id, translator_name, text,
                             created_at, updated_at)
VALUES
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not argue with the People of the Scripture except in a way that is best, except for those who commit injustice among them, and say, "We believe in that which has been revealed to us and revealed to you. And our God and your God is one; and we are Muslims [in submission] to Him."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And thus We have sent down to you the Qur''an. And those to whom We [previously] gave the Scripture believe in it. And among these [people of Makkah] are those who believe in it. And none reject Our verses except the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you did not recite before it any scripture, nor did you inscribe one with your right hand. Otherwise the falsifiers would have had [cause for] doubt.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, the Qur''an is distinct verses [preserved] within the breasts of those who have been given knowledge. And none reject Our verses except the wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they say, "Why are not signs sent down to him from his Lord?" Say, "The signs are only with Allah, and I am only a clear warner."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And is it not sufficient for them that We revealed to you the Book which is recited to them? Indeed in that is a mercy and reminder for a people who believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Sufficient is Allah between me and you as Witness. He knows what is in the heavens and earth. And they who have believed in falsehood and disbelieved in Allah - it is those who are the losers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they urge you to hasten the punishment. And if not for [the decree of] a specified term, punishment would have reached them. But it will surely come to them suddenly while they perceive not.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They urge you to hasten the punishment. And indeed, Hell will be encompassing of the disbelievers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On the Day the punishment will cover them from above them and from below their feet and it is said, "Taste [the result of] what you used to do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O My servants who have believed, indeed My earth is spacious, so worship only Me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Every soul will taste death. Then to Us will you be returned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who have believed and done righteous deeds - We will surely assign to them of Paradise [elevated] chambers beneath which rivers flow, wherein they abide eternally. Excellent is the reward of the [righteous] workers', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who have been patient and upon their Lord rely.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And how many a creature carries not its [own] provision. Allah provides for it and for you. And He is the Hearing, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If you asked them, "Who created the heavens and earth and subjected the sun and the moon?" they would surely say, "Allah." Then how are they deluded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah extends provision for whom He wills of His servants and restricts for him. Indeed Allah is, of all things, Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you asked them, "Who sends down rain from the sky and gives life thereby to the earth after its lifelessness?" they would surely say " Allah." Say, "Praise to Allah "; but most of them do not reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And this worldly life is not but diversion and amusement. And indeed, the home of the Hereafter - that is the [eternal] life, if only they knew.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they board a ship, they supplicate Allah, sincere to Him in religion. But when He delivers them to the land, at once they associate others with Him', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So that they will deny what We have granted them, and they will enjoy themselves. But they are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not seen that We made [Makkah] a safe sanctuary, while people are being taken away all around them? Then in falsehood do they believe, and in the favor of Allah they disbelieve?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And who is more unjust than one who invents a lie about Allah or denies the truth when it has come to him? Is there not in Hell a [sufficient] residence for the disbelievers?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 29 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who strive for Us - We will surely guide them to Our ways. And indeed, Allah is with the doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Byzantines have been defeated', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In the nearest land. But they, after their defeat, will overcome.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Within three to nine years. To Allah belongs the command before and after. And that day the believers will rejoice', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In the victory of Allah. He gives victory to whom He wills, and He is the Exalted in Might, the Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is] the promise of Allah. Allah does not fail in His promise, but most of the people do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They know what is apparent of the worldly life, but they, of the Hereafter, are unaware.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not contemplate within themselves? Allah has not created the heavens and the earth and what is between them except in truth and for a specified term. And indeed, many of the people, in [the matter of] the meeting with their Lord, are disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not traveled through the earth and observed how was the end of those before them? They were greater than them in power, and they plowed the earth and built it up more than they have built it up, and their messengers came to them with clear evidences. And Allah would not ever have wronged them, but they were wronging themselves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then the end of those who did evil was the worst [consequence] because they denied the signs of Allah and used to ridicule them.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah begins creation; then He will repeat it; then to Him you will be returned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the Day the Hour appears the criminals will be in despair.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there will not be for them among their [alleged] partners any intercessors, and they will [then] be disbelievers in their partners.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the Day the Hour appears - that Day they will become separated.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And as for those who had believed and done righteous deeds, they will be in a garden [of Paradise], delighted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for those who disbelieved and denied Our verses and the meeting of the Hereafter, those will be brought into the punishment [to remain].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So exalted is Allah when you reach the evening and when you reach the morning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Him is [due all] praise throughout the heavens and the earth. And [exalted is He] at night and when you are at noon.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He brings the living out of the dead and brings the dead out of the living and brings to life the earth after its lifelessness. And thus will you be brought out.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs is that He created you from dust; then, suddenly you were human beings dispersing [throughout the earth].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs is that He created for you from yourselves mates that you may find tranquillity in them; and He placed between you affection and mercy. Indeed in that are signs for a people who give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs is the creation of the heavens and the earth and the diversity of your languages and your colors. Indeed in that are signs for those of knowledge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs is your sleep by night and day and your seeking of His bounty. Indeed in that are signs for a people who listen.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs is [that] He shows you the lightning [causing] fear and aspiration, and He sends down rain from the sky by which He brings to life the earth after its lifelessness. Indeed in that are signs for a people who use reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs is that the heaven and earth remain by His command. Then when He calls you with a [single] call from the earth, immediately you will come forth.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Him belongs whoever is in the heavens and earth. All are to Him devoutly obedient.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is He who begins creation; then He repeats it, and that is [even] easier for Him. To Him belongs the highest attribute in the heavens and earth. And He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He presents to you an example from yourselves. Do you have among those whom your right hands possess any partners in what We have provided for you so that you are equal therein [and] would fear them as your fear of one another [within a partnership]? Thus do We detail the verses for a people who use reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who wrong follow their [own] desires without knowledge. Then who can guide one whom Allah has sent astray? And for them there are no helpers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So direct your face toward the religion, inclining to truth. [Adhere to] the fitrah of Allah upon which He has created [all] people. No change should there be in the creation of Allah. That is the correct religion, but most of the people do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Adhere to it], turning in repentance to Him, and fear Him and establish prayer and do not be of those who associate others with Allah', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Or] of those who have divided their religion and become sects, every faction rejoicing in what it has.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when adversity touches the people, they call upon their Lord, turning in repentance to Him. Then when He lets them taste mercy from Him, at once a party of them associate others with their Lord,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So that they will deny what We have granted them. Then enjoy yourselves, for you are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or have We sent down to them an authority, and it speaks of what they were associating with Him?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when We let the people taste mercy, they rejoice therein, but if evil afflicts them for what their hands have put forth, immediately they despair.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not see that Allah extends provision for whom He wills and restricts [it]? Indeed, in that are signs for a people who believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So give the relative his right, as well as the needy and the traveler. That is best for those who desire the countenance of Allah, and it is they who will be the successful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whatever you give for interest to increase within the wealth of people will not increase with Allah. But what you give in zakah, desiring the countenance of Allah - those are the multipliers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah is the one who created you, then provided for you, then will cause you to die, and then will give you life. Are there any of your "partners" who does anything of that? Exalted is He and high above what they associate with Him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Corruption has appeared throughout the land and sea by [reason of] what the hands of people have earned so He may let them taste part of [the consequence of] what they have done that perhaps they will return [to righteousness].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "Travel through the land and observe how was the end of those before. Most of them were associators [of others with Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So direct your face toward the correct religion before a Day comes from Allah of which there is no repelling. That Day, they will be divided.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever disbelieves - upon him is [the consequence of] his disbelief. And whoever does righteousness - they are for themselves preparing,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That He may reward those who have believed and done righteous deeds out of His bounty. Indeed, He does not like the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs is that He sends the winds as bringers of good tidings and to let you taste His mercy and so the ships may sail at His command and so you may seek of His bounty, and perhaps you will be grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have already sent messengers before you to their peoples, and they came to them with clear evidences; then We took retribution from those who committed crimes, and incumbent upon Us was support of the believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who sends the winds, and they stir the clouds and spread them in the sky however He wills, and He makes them fragments so you see the rain emerge from within them. And when He causes it to fall upon whom He wills of His servants, immediately they rejoice', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Although they were, before it was sent down upon them - before that, in despair.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So observe the effects of the mercy of Allah - how He gives life to the earth after its lifelessness. Indeed, that [same one] will give life to the dead, and He is over all things competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if We should send a [bad] wind and they saw [their crops] turned yellow, they would remain thereafter disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So indeed, you will not make the dead hear, nor will you make the deaf hear the call when they turn their backs, retreating.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you cannot guide the blind away from their error. You will only make hear those who believe in Our verses so they are Muslims [in submission to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah is the one who created you from weakness, then made after weakness strength, then made after strength weakness and white hair. He creates what He wills, and He is the Knowing, the Competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the Day the Hour appears the criminals will swear they had remained but an hour. Thus they were deluded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who were given knowledge and faith will say, "You remained the extent of Allah ''s decree until the Day of Resurrection, and this is the Day of Resurrection, but you did not used to know."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So that Day, their excuse will not benefit those who wronged, nor will they be asked to appease [Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have certainly presented to the people in this Qur''an from every [kind of] example. But, [O Muhammad], if you should bring them a sign, the disbelievers will surely say, "You [believers] are but falsifiers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thus does Allah seal the hearts of those who do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 30 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So be patient. Indeed, the promise of Allah is truth. And let them not disquiet you who are not certain [in faith].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'These are verses of the wise Book,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As guidance and mercy for the doers of good', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who establish prayer and give zakah, and they, of the Hereafter, are certain [in faith].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those are on [right] guidance from their Lord, and it is those who are the successful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of the people is he who buys the amusement of speech to mislead [others] from the way of Allah without knowledge and who takes it in ridicule. Those will have a humiliating punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when our verses are recited to him, he turns away arrogantly as if he had not heard them, as if there was in his ears deafness. So give him tidings of a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who believe and do righteous deeds - for them are the Gardens of Pleasure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Wherein they abide eternally; [it is] the promise of Allah [which is] truth. And He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He created the heavens without pillars that you see and has cast into the earth firmly set mountains, lest it should shift with you, and dispersed therein from every creature. And We sent down rain from the sky and made grow therein [plants] of every noble kind.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This is the creation of Allah. So show Me what those other than Him have created. Rather, the wrongdoers are in clear error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had certainly given Luqman wisdom [and said], "Be grateful to Allah." And whoever is grateful is grateful for [the benefit of] himself. And whoever denies [His favor] - then indeed, Allah is Free of need and Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention, O Muhammad], when Luqman said to his son while he was instructing him, "O my son, do not associate [anything] with Allah. Indeed, association [with him] is great injustice."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have enjoined upon man [care] for his parents. His mother carried him, [increasing her] in weakness upon weakness, and his weaning is in two years. Be grateful to Me and to your parents; to Me is the [final] destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if they endeavor to make you associate with Me that of which you have no knowledge, do not obey them but accompany them in [this] world with appropriate kindness and follow the way of those who turn back to Me [in repentance]. Then to Me will be your return, and I will inform you about what you used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[And Luqman said], "O my son, indeed if wrong should be the weight of a mustard seed and should be within a rock or [anywhere] in the heavens or in the earth, Allah will bring it forth. Indeed, Allah is Subtle and Acquainted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O my son, establish prayer, enjoin what is right, forbid what is wrong, and be patient over what befalls you. Indeed, [all] that is of the matters [requiring] determination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not turn your cheek [in contempt] toward people and do not walk through the earth exultantly. Indeed, Allah does not like everyone self-deluded and boastful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And be moderate in your pace and lower your voice; indeed, the most disagreeable of sounds is the voice of donkeys."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you not see that Allah has made subject to you whatever is in the heavens and whatever is in the earth and amply bestowed upon you His favors, [both] apparent and unapparent? But of the people is he who disputes about Allah without knowledge or guidance or an enlightening Book [from Him].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when it is said to them, "Follow what Allah has revealed," they say, "Rather, we will follow that upon which we found our fathers." Even if Satan was inviting them to the punishment of the Blaze?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever submits his face to Allah while he is a doer of good - then he has grasped the most trustworthy handhold. And to Allah will be the outcome of [all] matters.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever has disbelieved - let not his disbelief grieve you. To Us is their return, and We will inform them of what they did. Indeed, Allah is Knowing of that within the breasts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We grant them enjoyment for a little; then We will force them to a massive punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you asked them, "Who created the heavens and earth?" they would surely say, "Allah." Say, "[All] praise is [due] to Allah "; but most of them do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Allah belongs whatever is in the heavens and earth. Indeed, Allah is the Free of need, the Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if whatever trees upon the earth were pens and the sea [was ink], replenished thereafter by seven [more] seas, the words of Allah would not be exhausted. Indeed, Allah is Exalted in Might and Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Your creation and your resurrection will not be but as that of a single soul. Indeed, Allah is Hearing and Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you not see that Allah causes the night to enter the day and causes the day to enter the night and has subjected the sun and the moon, each running [its course] for a specified term, and that Allah, with whatever you do, is Acquainted?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is because Allah is the Truth, and that what they call upon other than Him is falsehood, and because Allah is the Most High, the Grand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you not see that ships sail through the sea by the favor of Allah that He may show you of His signs? Indeed in that are signs for everyone patient and grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when waves come over them like canopies, they supplicate Allah, sincere to Him in religion. But when He delivers them to the land, there are [some] of them who are moderate [in faith]. And none rejects Our signs except everyone treacherous and ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O mankind, fear your Lord and fear a Day when no father will avail his son, nor will a son avail his father at all. Indeed, the promise of Allah is truth, so let not the worldly life delude you and be not deceived about Allah by the Deceiver.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 31 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah [alone] has knowledge of the Hour and sends down the rain and knows what is in the wombs. And no soul perceives what it will earn tomorrow, and no soul perceives in what land it will die. Indeed, Allah is Knowing and Acquainted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Alif, Lam, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[This is] the revelation of the Book about which there is no doubt from the Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do they say, "He invented it"? Rather, it is the truth from your Lord, [O Muhammad], that you may warn a people to whom no warner has come before you [so] perhaps they will be guided.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who created the heavens and the earth and whatever is between them in six days; then He established Himself above the Throne. You have not besides Him any protector or any intercessor; so will you not be reminded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He arranges [each] matter from the heaven to the earth; then it will ascend to Him in a Day, the extent of which is a thousand years of those which you count.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is the Knower of the unseen and the witnessed, the Exalted in Might, the Merciful,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who perfected everything which He created and began the creation of man from clay.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then He made his posterity out of the extract of a liquid disdained.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then He proportioned him and breathed into him from His [created] soul and made for you hearing and vision and hearts; little are you grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "When we are lost within the earth, will we indeed be [recreated] in a new creation?" Rather, they are, in [the matter of] the meeting with their Lord, disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "The angel of death will take you who has been entrusted with you. Then to your Lord you will be returned."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If you could but see when the criminals are hanging their heads before their Lord, [saying], "Our Lord, we have seen and heard, so return us [to the world]; we will work righteousness. Indeed, we are [now] certain."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We had willed, We could have given every soul its guidance, but the word from Me will come into effect [that] "I will surely fill Hell with jinn and people all together.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So taste [punishment] because you forgot the meeting of this, your Day; indeed, We have [accordingly] forgotten you. And taste the punishment of eternity for what you used to do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Only those believe in Our verses who, when they are reminded by them, fall down in prostration and exalt [Allah] with praise of their Lord, and they are not arrogant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They arise from [their] beds; they supplicate their Lord in fear and aspiration, and from what We have provided them, they spend.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And no soul knows what has been hidden for them of comfort for eyes as reward for what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is one who was a believer like one who was defiantly disobedient? They are not equal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As for those who believed and did righteous deeds, for them will be the Gardens of Refuge as accommodation for what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for those who defiantly disobeyed, their refuge is the Fire. Every time they wish to emerge from it, they will be returned to it while it is said to them, "Taste the punishment of the Fire which you used to deny."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we will surely let them taste the nearer punishment short of the greater punishment that perhaps they will repent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And who is more unjust than one who is reminded of the verses of his Lord; then he turns away from them? Indeed We, from the criminals, will take retribution.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We certainly gave Moses the Scripture, so do not be in doubt over his meeting. And we made the Torah guidance for the Children of Israel.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We made from among them leaders guiding by Our command when they were patient and [when] they were certain of Our signs.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your Lord will judge between them on the Day of Resurrection concerning that over which they used to differ.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has it not become clear to them how many generations We destroyed before them, [as] they walk among their dwellings? Indeed in that are signs; then do they not hear?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not seen that We drive the water [in clouds] to barren land and bring forth thereby crops from which their livestock eat and [they] themselves? Then do they not see?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "When will be this conquest, if you should be truthful?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "On the Day of Conquest the belief of those who had disbelieved will not benefit them, nor will they be reprieved."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 32 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So turn away from them and wait. Indeed, they are waiting.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, fear Allah and do not obey the disbelievers and the hypocrites. Indeed, Allah is ever Knowing and Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And follow that which is revealed to you from your Lord. Indeed Allah is ever, with what you do, Acquainted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And rely upon Allah; and sufficient is Allah as Disposer of affairs.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah has not made for a man two hearts in his interior. And He has not made your wives whom you declare unlawful your mothers. And he has not made your adopted sons your [true] sons. That is [merely] your saying by your mouths, but Allah says the truth, and He guides to the [right] way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Call them by [the names of] their fathers; it is more just in the sight of Allah. But if you do not know their fathers - then they are [still] your brothers in religion and those entrusted to you. And there is no blame upon you for that in which you have erred but [only for] what your hearts intended. And ever is Allah Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Prophet is more worthy of the believers than themselves, and his wives are [in the position of] their mothers. And those of [blood] relationship are more entitled [to inheritance] in the decree of Allah than the [other] believers and the emigrants, except that you may do to your close associates a kindness [through bequest]. That was in the Book inscribed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention, O Muhammad], when We took from the prophets their covenant and from you and from Noah and Abraham and Moses and Jesus, the son of Mary; and We took from them a solemn covenant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That He may question the truthful about their truth. And He has prepared for the disbelievers a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, remember the favor of Allah upon you when armies came to [attack] you and We sent upon them a wind and armies [of angels] you did not see. And ever is Allah, of what you do, Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Remember] when they came at you from above you and from below you, and when eyes shifted [in fear], and hearts reached the throats and you assumed about Allah [various] assumptions.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There the believers were tested and shaken with a severe shaking.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [remember] when the hypocrites and those in whose hearts is disease said, "Allah and His Messenger did not promise us except delusion,"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when a faction of them said, "O people of Yathrib, there is no stability for you [here], so return [home]." And a party of them asked permission of the Prophet, saying, "Indeed, our houses are unprotected," while they were not exposed. They did not intend except to flee.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if they had been entered upon from all its [surrounding] regions and fitnah had been demanded of them, they would have done it and not hesitated over it except briefly.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they had already promised Allah before not to turn their backs and flee. And ever is the promise to Allah [that about which one will be] questioned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "Never will fleeing benefit you if you should flee from death or killing; and then [if you did], you would not be given enjoyment [of life] except for a little."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Who is it that can protect you from Allah if He intends for you an ill or intends for you a mercy?" And they will not find for themselves besides Allah any protector or any helper.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Already Allah knows the hinderers among you and those [hypocrites] who say to their brothers, "Come to us," and do not go to battle, except for a few,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indisposed toward you. And when fear comes, you see them looking at you, their eyes revolving like one being overcome by death. But when fear departs, they lash you with sharp tongues, indisposed toward [any] good. Those have not believed, so Allah has rendered their deeds worthless, and ever is that, for Allah, easy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They think the companies have not [yet] withdrawn. And if the companies should come [again], they would wish they were in the desert among the bedouins, inquiring [from afar] about your news. And if they should be among you, they would not fight except for a little.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There has certainly been for you in the Messenger of Allah an excellent pattern for anyone whose hope is in Allah and the Last Day and [who] remembers Allah often.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the believers saw the companies, they said, "This is what Allah and His Messenger had promised us, and Allah and His Messenger spoke the truth." And it increased them only in faith and acceptance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Among the believers are men true to what they promised Allah. Among them is he who has fulfilled his vow [to the death], and among them is he who awaits [his chance]. And they did not alter [the terms of their commitment] by any alteration -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That Allah may reward the truthful for their truth and punish the hypocrites if He wills or accept their repentance. Indeed, Allah is ever Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah repelled those who disbelieved, in their rage, not having obtained any good. And sufficient was Allah for the believers in battle, and ever is Allah Powerful and Exalted in Might.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He brought down those who supported them among the People of the Scripture from their fortresses and cast terror into their hearts [so that] a party you killed, and you took captive a party.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He caused you to inherit their land and their homes and their properties and a land which you have not trodden. And ever is Allah, over all things, competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, say to your wives, "If you should desire the worldly life and its adornment, then come, I will provide for you and give you a gracious release.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if you should desire Allah and His Messenger and the home of the Hereafter - then indeed, Allah has prepared for the doers of good among you a great reward."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O wives of the Prophet, whoever of you should commit a clear immorality - for her the punishment would be doubled two fold, and ever is that, for Allah, easy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever of you devoutly obeys Allah and His Messenger and does righteousness - We will give her her reward twice; and We have prepared for her a noble provision.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O wives of the Prophet, you are not like anyone among women. If you fear Allah, then do not be soft in speech [to men], lest he in whose heart is disease should covet, but speak with appropriate speech.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And abide in your houses and do not display yourselves as [was] the display of the former times of ignorance. And establish prayer and give zakah and obey Allah and His Messenger. Allah intends only to remove from you the impurity [of sin], O people of the [Prophet''s] household, and to purify you with [extensive] purification.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And remember what is recited in your houses of the verses of Allah and wisdom. Indeed, Allah is ever Subtle and Acquainted [with all things].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the Muslim men and Muslim women, the believing men and believing women, the obedient men and obedient women, the truthful men and truthful women, the patient men and patient women, the humble men and humble women, the charitable men and charitable women, the fasting men and fasting women, the men who guard their private parts and the women who do so, and the men who remember Allah often and the women who do so - for them Allah has prepared forgiveness and a great reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is not for a believing man or a believing woman, when Allah and His Messenger have decided a matter, that they should [thereafter] have any choice about their affair. And whoever disobeys Allah and His Messenger has certainly strayed into clear error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [remember, O Muhammad], when you said to the one on whom Allah bestowed favor and you bestowed favor, "Keep your wife and fear Allah," while you concealed within yourself that which Allah is to disclose. And you feared the people, while Allah has more right that you fear Him. So when Zayd had no longer any need for her, We married her to you in order that there not be upon the believers any discomfort concerning the wives of their adopted sons when they no longer have need of them. And ever is the command of Allah accomplished.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There is not to be upon the Prophet any discomfort concerning that which Allah has imposed upon him. [This is] the established way of Allah with those [prophets] who have passed on before. And ever is the command of Allah a destiny decreed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah praises] those who convey the messages of Allah and fear Him and do not fear anyone but Allah. And sufficient is Allah as Accountant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Muhammad is not the father of [any] one of your men, but [he is] the Messenger of Allah and last of the prophets. And ever is Allah, of all things, Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, remember Allah with much remembrance', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And exalt Him morning and afternoon.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who confers blessing upon you, and His angels [ask Him to do so] that He may bring you out from darknesses into the light. And ever is He, to the believers, Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Their greeting the Day they meet Him will be, "Peace." And He has prepared for them a noble reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, indeed We have sent you as a witness and a bringer of good tidings and a warner.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And one who invites to Allah, by His permission, and an illuminating lamp.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And give good tidings to the believers that they will have from Allah great bounty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And do not obey the disbelievers and the hypocrites but do not harm them, and rely upon Allah. And sufficient is Allah as Disposer of affairs.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O You who have believed, when you marry believing women and then divorce them before you have touched them, then there is not for you any waiting period to count concerning them. So provide for them and give them a gracious release.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, indeed We have made lawful to you your wives to whom you have given their due compensation and those your right hand possesses from what Allah has returned to you [of captives] and the daughters of your paternal uncles and the daughters of your paternal aunts and the daughters of your maternal uncles and the daughters of your maternal aunts who emigrated with you and a believing woman if she gives herself to the Prophet [and] if the Prophet wishes to marry her, [this is] only for you, excluding the [other] believers. We certainly know what We have made obligatory upon them concerning their wives and those their right hands possess, [but this is for you] in order that there will be upon you no discomfort. And ever is Allah Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You, [O Muhammad], may put aside whom you will of them or take to yourself whom you will. And any that you desire of those [wives] from whom you had [temporarily] separated - there is no blame upon you [in returning her]. That is more suitable that they should be content and not grieve and that they should be satisfied with what you have given them - all of them. And Allah knows what is in your hearts. And ever is Allah Knowing and Forbearing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Not lawful to you, [O Muhammad], are [any additional] women after [this], nor [is it] for you to exchange them for [other] wives, even if their beauty were to please you, except what your right hand possesses. And ever is Allah, over all things, an Observer.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, do not enter the houses of the Prophet except when you are permitted for a meal, without awaiting its readiness. But when you are invited, then enter; and when you have eaten, disperse without seeking to remain for conversation. Indeed, that [behavior] was troubling the Prophet, and he is shy of [dismissing] you. But Allah is not shy of the truth. And when you ask [his wives] for something, ask them from behind a partition. That is purer for your hearts and their hearts. And it is not [conceivable or lawful] for you to harm the Messenger of Allah or to marry his wives after him, ever. Indeed, that would be in the sight of Allah an enormity.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whether you reveal a thing or conceal it, indeed Allah is ever, of all things, Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There is no blame upon women concerning their fathers or their sons or their brothers or their brothers'' sons or their sisters'' sons or their women or those their right hands possess. And fear Allah. Indeed Allah is ever, over all things, Witness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah confers blessing upon the Prophet, and His angels [ask Him to do so]. O you who have believed, ask [Allah to confer] blessing upon him and ask [Allah to grant him] peace.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who abuse Allah and His Messenger - Allah has cursed them in this world and the Hereafter and prepared for them a humiliating punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who harm believing men and believing women for [something] other than what they have earned have certainly born upon themselves a slander and manifest sin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O Prophet, tell your wives and your daughters and the women of the believers to bring down over themselves [part] of their outer garments. That is more suitable that they will be known and not be abused. And ever is Allah Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If the hypocrites and those in whose hearts is disease and those who spread rumors in al-Madinah do not cease, We will surely incite you against them; then they will not remain your neighbors therein except for a little.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Accursed wherever they are found, [being] seized and massacred completely.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[This is] the established way of Allah with those who passed on before; and you will not find in the way of Allah any change.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'People ask you concerning the Hour. Say," Knowledge of it is only with Allah. And what may make you perceive? Perhaps the Hour is near."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah has cursed the disbelievers and prepared for them a Blaze.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Abiding therein forever, they will not find a protector or a helper.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day their faces will be turned about in the Fire, they will say, "How we wish we had obeyed Allah and obeyed the Messenger."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will say, "Our Lord, indeed we obeyed our masters and our dignitaries, and they led us astray from the [right] way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Our Lord, give them double the punishment and curse them with a great curse."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, be not like those who abused Moses; then Allah cleared him of what they said. And he, in the sight of Allah, was distinguished.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O you who have believed, fear Allah and speak words of appropriate justice.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will [then] amend for you your deeds and forgive you your sins. And whoever obeys Allah and His Messenger has certainly attained a great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, we offered the Trust to the heavens and the earth and the mountains, and they declined to bear it and feared it; but man [undertook to] bear it. Indeed, he was unjust and ignorant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 33 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It was] so that Allah may punish the hypocrite men and hypocrite women and the men and women who associate others with Him and that Allah may accept repentance from the believing men and believing women. And ever is Allah Forgiving and Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[All] praise is [due] to Allah, to whom belongs whatever is in the heavens and whatever is in the earth, and to Him belongs [all] praise in the Hereafter. And He is the Wise, the Acquainted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He knows what penetrates into the earth and what emerges from it and what descends from the heaven and what ascends therein. And He is the Merciful, the Forgiving.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who disbelieve say, "The Hour will not come to us." Say, "Yes, by my Lord, it will surely come to you. [Allah is] the Knower of the unseen." Not absent from Him is an atom''s weight within the heavens or within the earth or [what is] smaller than that or greater, except that it is in a clear register -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That He may reward those who believe and do righteous deeds. Those will have forgiveness and noble provision.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who strive against Our verses [seeking] to cause failure - for them will be a painful punishment of foul nature.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who have been given knowledge see that what is revealed to you from your Lord is the truth, and it guides to the path of the Exalted in Might, the Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who disbelieve say, "Shall we direct you to a man who will inform you [that] when you have disintegrated in complete disintegration, you will [then] be [recreated] in a new creation?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has he invented about Allah a lie or is there in him madness?" Rather, they who do not believe in the Hereafter will be in the punishment and [are in] extreme error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, do they not look at what is before them and what is behind them of the heaven and earth? If We should will, We could cause the earth to swallow them or [could] let fall upon them fragments from the sky. Indeed in that is a sign for every servant turning back [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We certainly gave David from Us bounty. [We said], "O mountains, repeat [Our] praises with him, and the birds [as well]." And We made pliable for him iron,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Commanding him], "Make full coats of mail and calculate [precisely] the links, and work [all of you] righteousness. Indeed I, of what you do, am Seeing."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Solomon [We subjected] the wind - its morning [journey was that of] a month - and its afternoon [journey was that of] a month, and We made flow for him a spring of [liquid] copper. And among the jinn were those who worked for him by the permission of his Lord. And whoever deviated among them from Our command - We will make him taste of the punishment of the Blaze.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They made for him what he willed of elevated chambers, statues, bowls like reservoirs, and stationary kettles. [We said], "Work, O family of David, in gratitude." And few of My servants are grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when We decreed for Solomon death, nothing indicated to the jinn his death except a creature of the earth eating his staff. But when he fell, it became clear to the jinn that if they had known the unseen, they would not have remained in humiliating punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There was for [the tribe of] Saba'' in their dwelling place a sign: two [fields of] gardens on the right and on the left. [They were told], "Eat from the provisions of your Lord and be grateful to Him. A good land [have you], and a forgiving Lord."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they turned away [refusing], so We sent upon them the flood of the dam, and We replaced their two [fields of] gardens with gardens of bitter fruit, tamarisks and something of sparse lote trees.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[By] that We repaid them because they disbelieved. And do We [thus] repay except the ungrateful?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We placed between them and the cities which We had blessed [many] visible cities. And We determined between them the [distances of] journey, [saying], "Travel between them by night or day in safety."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But [insolently] they said, "Our Lord, lengthen the distance between our journeys," and wronged themselves, so We made them narrations and dispersed them in total dispersion. Indeed in that are signs for everyone patient and grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Iblees had already confirmed through them his assumption, so they followed him, except for a party of believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he had over them no authority except [it was decreed] that We might make evident who believes in the Hereafter from who is thereof in doubt. And your Lord, over all things, is Guardian.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "Invoke those you claim [as deities] besides Allah." They do not possess an atom''s weight [of ability] in the heavens or on the earth, and they do not have therein any partnership [with Him], nor is there for Him from among them any assistant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And intercession does not benefit with Him except for one whom He permits. [And those wait] until, when terror is removed from their hearts, they will say [to one another], "What has your Lord said?" They will say, "The truth." And He is the Most High, the Grand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Who provides for you from the heavens and the earth?" Say, "Allah. And indeed, we or you are either upon guidance or in clear error."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "You will not be asked about what we committed, and we will not be asked about what you do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Our Lord will bring us together; then He will judge between us in truth. And He is the Knowing Judge."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Show me those whom you have attached to Him as partners. No! Rather, He [alone] is Allah, the Exalted in Might, the Wise."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have not sent you except comprehensively to mankind as a bringer of good tidings and a warner. But most of the people do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "When is this promise, if you should be truthful?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "For you is the appointment of a Day [when] you will not remain thereafter an hour, nor will you precede [it]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who disbelieve say, "We will never believe in this Qur''an nor in that before it." But if you could see when the wrongdoers are made to stand before their Lord, refuting each other''s words... Those who were oppressed will say to those who were arrogant, "If not for you, we would have been believers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who were arrogant will say to those who were oppressed, "Did we avert you from guidance after it had come to you? Rather, you were criminals."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who were oppressed will say to those who were arrogant, "Rather, [it was your] conspiracy of night and day when you were ordering us to disbelieve in Allah and attribute to Him equals." But they will [all] confide regret when they see the punishment; and We will put shackles on the necks of those who disbelieved. Will they be recompensed except for what they used to do?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not send into a city any warner except that its affluent said, "Indeed we, in that with which you were sent, are disbelievers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they said, "We are more [than the believers] in wealth and children, and we are not to be punished."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Indeed, my Lord extends provision for whom He wills and restricts [it], but most of the people do not know."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is not your wealth or your children that bring you nearer to Us in position, but it is [by being] one who has believed and done righteousness. For them there will be the double reward for what they did, and they will be in the upper chambers [of Paradise], safe [and secure].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the ones who strive against Our verses to cause [them] failure - those will be brought into the punishment [to remain].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Indeed, my Lord extends provision for whom He wills of His servants and restricts [it] for him. But whatever thing you spend [in His cause] - He will compensate it; and He is the best of providers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention] the Day when He will gather them all and then say to the angels, "Did these [people] used to worship you?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "Exalted are You! You, [O Allah], are our benefactor not them. Rather, they used to worship the jinn; most of them were believers in them."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But today you do not hold for one another [the power of] benefit or harm, and We will say to those who wronged, "Taste the punishment of the Fire, which you used to deny."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when our verses are recited to them as clear evidences, they say, "This is not but a man who wishes to avert you from that which your fathers were worshipping." And they say, "This is not except a lie invented." And those who disbelieve say of the truth when it has come to them, "This is not but obvious magic."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had not given them any scriptures which they could study, and We had not sent to them before you, [O Muhammad], any warner.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those before them denied, and the people of Makkah have not attained a tenth of what We had given them. But the former peoples denied My messengers, so how [terrible] was My reproach.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "I only advise you of one [thing] - that you stand for Allah, [seeking truth] in pairs and individually, and then give thought." There is not in your companion any madness. He is only a warner to you before a severe punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Whatever payment I might have asked of you - it is yours. My payment is only from Allah, and He is, over all things, Witness."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Indeed, my Lord projects the truth. Knower of the unseen."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "The truth has come, and falsehood can neither begin [anything] nor repeat [it]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "If I should err, I would only err against myself. But if I am guided, it is by what my Lord reveals to me. Indeed, He is Hearing and near."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you could see when they are terrified but there is no escape, and they will be seized from a place nearby.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will [then] say, "We believe in it!" But how for them will be the taking [of faith] from a place far away?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they had already disbelieved in it before and would assault the unseen from a place far away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 34 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And prevention will be placed between them and what they desire, as was done with their kind before. Indeed, they were in disquieting denial.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[All] praise is [due] to Allah, Creator of the heavens and the earth, [who] made the angels messengers having wings, two or three or four. He increases in creation what He wills. Indeed, Allah is over all things competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whatever Allah grants to people of mercy - none can withhold it; and whatever He withholds - none can release it thereafter. And He is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O mankind, remember the favor of Allah upon you. Is there any creator other than Allah who provides for you from the heaven and earth? There is no deity except Him, so how are you deluded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if they deny you, [O Muhammad] - already were messengers denied before you. And to Allah are returned [all] matters.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O mankind, indeed the promise of Allah is truth, so let not the worldly life delude you and be not deceived about Allah by the Deceiver.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Satan is an enemy to you; so take him as an enemy. He only invites his party to be among the companions of the Blaze.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who disbelieve will have a severe punishment, and those who believe and do righteous deeds will have forgiveness and great reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is one to whom the evil of his deed has been made attractive so he considers it good [like one rightly guided]? For indeed, Allah sends astray whom He wills and guides whom He wills. So do not let yourself perish over them in regret. Indeed, Allah is Knowing of what they do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is Allah who sends the winds, and they stir the clouds, and We drive them to a dead land and give life thereby to the earth after its lifelessness. Thus is the resurrection.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever desires honor [through power] - then to Allah belongs all honor. To Him ascends good speech, and righteous work raises it. But they who plot evil deeds will have a severe punishment, and the plotting of those - it will perish.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah created you from dust, then from a sperm-drop; then He made you mates. And no female conceives nor does she give birth except with His knowledge. And no aged person is granted [additional] life nor is his lifespan lessened but that it is in a register. Indeed, that for Allah is easy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And not alike are the two bodies of water. One is fresh and sweet, palatable for drinking, and one is salty and bitter. And from each you eat tender meat and extract ornaments which you wear, and you see the ships plowing through [them] that you might seek of His bounty; and perhaps you will be grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He causes the night to enter the day, and He causes the day to enter the night and has subjected the sun and the moon - each running [its course] for a specified term. That is Allah, your Lord; to Him belongs sovereignty. And those whom you invoke other than Him do not possess [as much as] the membrane of a date seed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If you invoke them, they do not hear your supplication; and if they heard, they would not respond to you. And on the Day of Resurrection they will deny your association. And none can inform you like [one] Acquainted [with all matters].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O mankind, you are those in need of Allah, while Allah is the Free of need, the Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If He wills, He can do away with you and bring forth a new creation.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that is for Allah not difficult.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And no bearer of burdens will bear the burden of another. And if a heavily laden soul calls [another] to [carry some of] its load, nothing of it will be carried, even if he should be a close relative. You can only warn those who fear their Lord unseen and have established prayer. And whoever purifies himself only purifies himself for [the benefit of] his soul. And to Allah is the [final] destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Not equal are the blind and the seeing,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor are the darknesses and the light,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nor are the shade and the heat,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And not equal are the living and the dead. Indeed, Allah causes to hear whom He wills, but you cannot make hear those in the graves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You, [O Muhammad], are not but a warner.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have sent you with the truth as a bringer of good tidings and a warner. And there was no nation but that there had passed within it a warner.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if they deny you - then already have those before them denied. Their messengers came to them with clear proofs and written ordinances and with the enlightening Scripture.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then I seized the ones who disbelieved, and how [terrible] was My reproach.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you not see that Allah sends down rain from the sky, and We produce thereby fruits of varying colors? And in the mountains are tracts, white and red of varying shades and [some] extremely black.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And among people and moving creatures and grazing livestock are various colors similarly. Only those fear Allah, from among His servants, who have knowledge. Indeed, Allah is Exalted in Might and Forgiving.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who recite the Book of Allah and establish prayer and spend [in His cause] out of what We have provided them, secretly and publicly, [can] expect a profit that will never perish -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That He may give them in full their rewards and increase for them of His bounty. Indeed, He is Forgiving and Appreciative.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that which We have revealed to you, [O Muhammad], of the Book is the truth, confirming what was before it. Indeed, Allah, of His servants, is Acquainted and Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then we caused to inherit the Book those We have chosen of Our servants; and among them is he who wrongs himself, and among them is he who is moderate, and among them is he who is foremost in good deeds by permission of Allah. That [inheritance] is what is the great bounty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[For them are] gardens of perpetual residence which they will enter. They will be adorned therein with bracelets of gold and pearls, and their garments therein will be silk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will say, "Praise to Allah, who has removed from us [all] sorrow. Indeed, our Lord is Forgiving and Appreciative -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He who has settled us in the home of duration out of His bounty. There touches us not in it any fatigue, and there touches us not in it weariness [of mind]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And for those who disbelieve will be the fire of Hell. [Death] is not decreed for them so they may die, nor will its torment be lightened for them. Thus do we recompense every ungrateful one.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will cry out therein, "Our Lord, remove us; we will do righteousness - other than what we were doing!" But did We not grant you life enough for whoever would remember therein to remember, and the warner had come to you? So taste [the punishment], for there is not for the wrongdoers any helper.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah is Knower of the unseen [aspects] of the heavens and earth. Indeed, He is Knowing of that within the breasts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who has made you successors upon the earth. And whoever disbelieves - upon him will be [the consequence of] his disbelief. And the disbelief of the disbelievers does not increase them in the sight of their Lord except in hatred; and the disbelief of the disbelievers does not increase them except in loss.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Have you considered your ''partners'' whom you invoke besides Allah? Show me what they have created from the earth, or have they partnership [with Him] in the heavens? Or have We given them a book so they are [standing] on evidence therefrom? [No], rather, the wrongdoers do not promise each other except delusion."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah holds the heavens and the earth, lest they cease. And if they should cease, no one could hold them [in place] after Him. Indeed, He is Forbearing and Forgiving.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they swore by Allah their strongest oaths that if a warner came to them, they would be more guided than [any] one of the [previous] nations. But when a warner came to them, it did not increase them except in aversion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Due to] arrogance in the land and plotting of evil; but the evil plot does not encompass except its own people. Then do they await except the way of the former peoples? But you will never find in the way of Allah any change, and you will never find in the way of Allah any alteration.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not traveled through the land and observed how was the end of those before them? And they were greater than them in power. But Allah is not to be caused failure by anything in the heavens or on the earth. Indeed, He is ever Knowing and Competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 35 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if Allah were to impose blame on the people for what they have earned, He would not leave upon the earth any creature. But He defers them for a specified term. And when their time comes, then indeed Allah has ever been, of His servants, Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Ya, Seen.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By the wise Qur''an.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed you, [O Muhammad], are from among the messengers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On a straight path.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[This is] a revelation of the Exalted in Might, the Merciful,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That you may warn a people whose forefathers were not warned, so they are unaware.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Already the word has come into effect upon most of them, so they do not believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have put shackles on their necks, and they are to their chins, so they are with heads [kept] aloft.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have put before them a barrier and behind them a barrier and covered them, so they do not see.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is all the same for them whether you warn them or do not warn them - they will not believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You can only warn one who follows the message and fears the Most Merciful unseen. So give him good tidings of forgiveness and noble reward.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, it is We who bring the dead to life and record what they have put forth and what they left behind, and all things We have enumerated in a clear register.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And present to them an example: the people of the city, when the messengers came to it -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When We sent to them two but they denied them, so We strengthened them with a third, and they said, "Indeed, we are messengers to you."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "You are not but human beings like us, and the Most Merciful has not revealed a thing. You are only telling lies."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Our Lord knows that we are messengers to you,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we are not responsible except for clear notification."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Indeed, we consider you a bad omen. If you do not desist, we will surely stone you, and there will surely touch you, from us, a painful punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Your omen is with yourselves. Is it because you were reminded? Rather, you are a transgressing people."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there came from the farthest end of the city a man, running. He said, "O my people, follow the messengers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Follow those who do not ask of you [any] payment, and they are [rightly] guided.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And why should I not worship He who created me and to whom you will be returned?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Should I take other than Him [false] deities [while], if the Most Merciful intends for me some adversity, their intercession will not avail me at all, nor can they save me?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, I would then be in manifest error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, I have believed in your Lord, so listen to me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It was said, "Enter Paradise." He said, "I wish my people could know', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Of how my Lord has forgiven me and placed me among the honored."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not send down upon his people after him any soldiers from the heaven, nor would We have done so.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It was not but one shout, and immediately they were extinguished.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'How regretful for the servants. There did not come to them any messenger except that they used to ridicule him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not considered how many generations We destroyed before them - that they to them will not return?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, all of them will yet be brought present before Us.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And a sign for them is the dead earth. We have brought it to life and brought forth from it grain, and from it they eat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We placed therein gardens of palm trees and grapevines and caused to burst forth therefrom some springs -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That they may eat of His fruit. And their hands have not produced it, so will they not be grateful?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Exalted is He who created all pairs - from what the earth grows and from themselves and from that which they do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And a sign for them is the night. We remove from it [the light of] day, so they are [left] in darkness.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the sun runs [on course] toward its stopping point. That is the determination of the Exalted in Might, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the moon - We have determined for it phases, until it returns [appearing] like the old date stalk.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is not allowable for the sun to reach the moon, nor does the night overtake the day, but each, in an orbit, is swimming.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And a sign for them is that We carried their forefathers in a laden ship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We created for them from the likes of it that which they ride.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We should will, We could drown them; then no one responding to a cry would there be for them, nor would they be saved', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except as a mercy from Us and provision for a time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when it is said to them, "Beware of what is before you and what is behind you; perhaps you will receive mercy... "', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And no sign comes to them from the signs of their Lord except that they are from it turning away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when it is said to them, "Spend from that which Allah has provided for you," those who disbelieve say to those who believe, "Should we feed one whom, if Allah had willed, He would have fed? You are not but in clear error."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "When is this promise, if you should be truthful?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They do not await except one blast which will seize them while they are disputing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will not be able [to give] any instruction, nor to their people can they return.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the Horn will be blown; and at once from the graves to their Lord they will hasten.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "O woe to us! Who has raised us up from our sleeping place?" [The reply will be], "This is what the Most Merciful had promised, and the messengers told the truth."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It will not be but one blast, and at once they are all brought present before Us.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So today no soul will be wronged at all, and you will not be recompensed except for what you used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed the companions of Paradise, that Day, will be amused in [joyful] occupation -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They and their spouses - in shade, reclining on adorned couches.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For them therein is fruit, and for them is whatever they request [or wish]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[And] "Peace," a word from a Merciful Lord.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Then He will say], "But stand apart today, you criminals.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Did I not enjoin upon you, O children of Adam, that you not worship Satan - [for] indeed, he is to you a clear enemy -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that you worship [only] Me? This is a straight path.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he had already led astray from among you much of creation, so did you not use reason?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This is the Hellfire which you were promised.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Enter to] burn therein today for what you used to deny."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That Day, We will seal over their mouths, and their hands will speak to Us, and their feet will testify about what they used to earn.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We willed, We could have obliterated their eyes, and they would race to [find] the path, and how could they see?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We willed, We could have deformed them, [paralyzing them] in their places so they would not be able to proceed, nor could they return.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he to whom We grant long life We reverse in creation; so will they not understand?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not give Prophet Muhammad, knowledge of poetry, nor is it befitting for him. It is not but a message and a clear Qur''an', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To warn whoever is alive and justify the word against the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not see that We have created for them from what Our hands have made, grazing livestock, and [then] they are their owners?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have tamed them for them, so some of them they ride, and some of them they eat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And for them therein are [other] benefits and drinks, so will they not be grateful?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they have taken besides Allah [false] deities that perhaps they would be helped.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They are not able to help them, and they [themselves] are for them soldiers in attendance.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So let not their speech grieve you. Indeed, We know what they conceal and what they declare.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Does man not consider that We created him from a [mere] sperm-drop - then at once he is a clear adversary?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he presents for Us an example and forgets his [own] creation. He says, "Who will give life to bones while they are disintegrated?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "He will give them life who produced them the first time; and He is, of all creation, Knowing."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is] He who made for you from the green tree, fire, and then from it you ignite.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is not He who created the heavens and the earth Able to create the likes of them? Yes, [it is so]; and He is the Knowing Creator.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'His command is only when He intends a thing that He says to it, "Be," and it is.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 36 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So exalted is He in whose hand is the realm of all things, and to Him you will be returned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By those [angels] lined up in rows', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who drive [the clouds]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who recite the message,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, your God is One,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Lord of the heavens and the earth and that between them and Lord of the sunrises.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have adorned the nearest heaven with an adornment of stars', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And as protection against every rebellious devil', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[So] they may not listen to the exalted assembly [of angels] and are pelted from every side,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Repelled; and for them is a constant punishment,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except one who snatches [some words] by theft, but they are pursued by a burning flame, piercing [in brightness].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then inquire of them, [O Muhammad], "Are they a stronger [or more difficult] creation or those [others] We have created?" Indeed, We created men from sticky clay.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But you wonder, while they mock,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they are reminded, they remember not.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they see a sign, they ridicule', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And say, "This is not but obvious magic.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When we have died and become dust and bones, are we indeed to be resurrected?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And our forefathers [as well]?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Yes, and you will be [rendered] contemptible."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It will be only one shout, and at once they will be observing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "O woe to us! This is the Day of Recompense."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will be told], "This is the Day of Judgement which you used to deny."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The angels will be ordered], "Gather those who committed wrong, their kinds, and what they used to worship', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Other than Allah, and guide them to the path of Hellfire', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And stop them; indeed, they are to be questioned."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will be asked], "What is [wrong] with you? Why do you not help each other?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they, that Day, are in surrender.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will approach one another blaming each other.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "Indeed, you used to come at us from the right."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The oppressors will say, "Rather, you [yourselves] were not believers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we had over you no authority, but you were a transgressing people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So the word of our Lord has come into effect upon us; indeed, we will taste [punishment].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And we led you to deviation; indeed, we were deviators."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So indeed they, that Day, will be sharing in the punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, that is how We deal with the criminals.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed they, when it was said to them, "There is no deity but Allah," were arrogant', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And were saying, "Are we to leave our gods for a mad poet?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, the Prophet has come with the truth and confirmed the [previous] messengers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, you [disbelievers] will be tasters of the painful punishment,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you will not be recompensed except for what you used to do -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But not the chosen servants of Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those will have a provision determined -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Fruits; and they will be honored', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In gardens of pleasure', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On thrones facing one another.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There will be circulated among them a cup [of wine] from a flowing spring,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'White and delicious to the drinkers;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No bad effect is there in it, nor from it will they be intoxicated.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And with them will be women limiting [their] glances, with large, [beautiful] eyes,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As if they were [delicate] eggs, well-protected.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will approach one another, inquiring of each other.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A speaker among them will say, "Indeed, I had a companion [on earth]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who would say, ''Are you indeed of those who believe', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That when we have died and become dust and bones, we will indeed be recompensed?''"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will say, "Would you [care to] look?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he will look and see him in the midst of the Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He will say, "By Allah, you almost ruined me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If not for the favor of my Lord, I would have been of those brought in [to Hell].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, are we not to die', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except for our first death, and we will not be punished?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, this is the great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For the like of this let the workers [on earth] work.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is Paradise a better accommodation or the tree of zaqqum?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have made it a torment for the wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, it is a tree issuing from the bottom of the Hellfire,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Its emerging fruit as if it was heads of the devils.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, they will eat from it and fill with it their bellies.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then indeed, they will have after it a mixture of scalding water.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then indeed, their return will be to the Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed they found their fathers astray.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So they hastened [to follow] in their footsteps.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there had already strayed before them most of the former peoples,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had already sent among them warners.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then look how was the end of those who were warned -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But not the chosen servants of Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Noah had certainly called Us, and [We are] the best of responders.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We saved him and his family from the great affliction.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We made his descendants those remaining [on the earth]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And left for him [favorable mention] among later generations:', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '"Peace upon Noah among the worlds."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We thus reward the doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, he was of Our believing servants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We drowned the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, among his kind was Abraham,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When he came to his Lord with a sound heart', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[And] when he said to his father and his people, "What do you worship?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is it falsehood [as] gods other than Allah you desire?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then what is your thought about the Lord of the worlds?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he cast a look at the stars', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And said, "Indeed, I am [about to be] ill."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 90), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So they turned away from him, departing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 91), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then he turned to their gods and said, "Do you not eat?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 92), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'What is [wrong] with you that you do not speak?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 93), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he turned upon them a blow with [his] right hand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 94), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then the people came toward him, hastening.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 95), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "Do you worship that which you [yourselves] carve,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'While Allah created you and that which you do?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 97), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They said, "Construct for him a furnace and throw him into the burning fire."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they intended for him a plan, but We made them the most debased.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [then] he said, "Indeed, I will go to [where I am ordered by] my Lord; He will guide me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'My Lord, grant me [a child] from among the righteous."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So We gave him good tidings of a forbearing boy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when he reached with him [the age of] exertion, he said, "O my son, indeed I have seen in a dream that I [must] sacrifice you, so see what you think." He said, "O my father, do as you are commanded. You will find me, if Allah wills, of the steadfast."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they had both submitted and he put him down upon his forehead,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 104), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We called to him, "O Abraham,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 105), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You have fulfilled the vision." Indeed, We thus reward the doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 106), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, this was the clear trial.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 107), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We ransomed him with a great sacrifice,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 108), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We left for him [favorable mention] among later generations:', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 109), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '"Peace upon Abraham."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 110), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We thus reward the doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 111), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, he was of Our believing servants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 112), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We gave him good tidings of Isaac, a prophet from among the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 113), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We blessed him and Isaac. But among their descendants is the doer of good and the clearly unjust to himself.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 114), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did certainly confer favor upon Moses and Aaron.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 115), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We saved them and their people from the great affliction,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 116), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We supported them so it was they who overcame.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 117), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We gave them the explicit Scripture,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 118), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We guided them on the straight path.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 119), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We left for them [favorable mention] among later generations:', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 120), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '"Peace upon Moses and Aaron."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 121), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We thus reward the doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 122), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, they were of Our believing servants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 123), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, Elias was from among the messengers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 124), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When he said to his people, "Will you not fear Allah?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 125), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you call upon Ba''l and leave the best of creators -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 126), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah, your Lord and the Lord of your first forefathers?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 127), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they denied him, so indeed, they will be brought [for punishment],', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 128), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except the chosen servants of Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 129), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We left for him [favorable mention] among later generations:', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 130), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '"Peace upon Elias."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 131), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We thus reward the doers of good.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 132), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, he was of Our believing servants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 133), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, Lot was among the messengers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 134), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[So mention] when We saved him and his family, all,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 135), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except his wife among those who remained [with the evildoers].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 136), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We destroyed the others.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 137), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, you pass by them in the morning', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 138), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And at night. Then will you not use reason?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 139), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, Jonah was among the messengers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 140), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Mention] when he ran away to the laden ship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 141), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he drew lots and was among the losers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 142), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then the fish swallowed him, while he was blameworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 143), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And had he not been of those who exalt Allah,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 144), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He would have remained inside its belly until the Day they are resurrected.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 145), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But We threw him onto the open shore while he was ill.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 146), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We caused to grow over him a gourd vine.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 147), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We sent him to [his people of] a hundred thousand or more.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 148), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they believed, so We gave them enjoyment [of life] for a time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 149), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So inquire of them, [O Muhammad], "Does your Lord have daughters while they have sons?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 150), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or did We create the angels as females while they were witnesses?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 151), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Unquestionably, it is out of their [invented] falsehood that they say,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 152), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '" Allah has begotten," and indeed, they are liars.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 153), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has He chosen daughters over sons?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 154), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'What is [wrong] with you? How do you make judgement?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 155), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then will you not be reminded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 156), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do you have a clear authority?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 157), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then produce your scripture, if you should be truthful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 158), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they have claimed between Him and the jinn a lineage, but the jinn have already known that they [who made such claims] will be brought to [punishment].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 159), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Exalted is Allah above what they describe,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 160), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except the chosen servants of Allah [who do not share in that sin].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 161), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So indeed, you [disbelievers] and whatever you worship,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 162), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You cannot tempt [anyone] away from Him', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 163), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except he who is to [enter and] burn in the Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 164), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The angels say], "There is not among us any except that he has a known position.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 165), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, we are those who line up [for prayer].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 166), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, we are those who exalt Allah."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 167), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, the disbelievers used to say,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 168), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '"If we had a message from [those of] the former peoples,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 169), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We would have been the chosen servants of Allah."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 170), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they disbelieved in it, so they are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 171), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Our word has already preceded for Our servants, the messengers,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 172), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[That] indeed, they would be those given victory', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 173), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [that] indeed, Our soldiers will be those who overcome.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 174), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So, [O Muhammad], leave them for a time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 175), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And see [what will befall] them, for they are going to see.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 176), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then for Our punishment are they impatient?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 177), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when it descends in their territory, then evil is the morning of those who were warned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 178), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And leave them for a time.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 179), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And see, for they are going to see.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 180), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Exalted is your Lord, the Lord of might, above what they describe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 181), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And peace upon the messengers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 37 AND a.ayah_number = 182), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And praise to Allah, Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Sad. By the Qur''an containing reminder...', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who disbelieve are in pride and dissension.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'How many a generation have We destroyed before them, and they [then] called out; but it was not a time for escape.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they wonder that there has come to them a warner from among themselves. And the disbelievers say, "This is a magician and a liar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has he made the gods [only] one God? Indeed, this is a curious thing."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the eminent among them went forth, [saying], "Continue, and be patient over [the defense of] your gods. Indeed, this is a thing intended.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We have not heard of this in the latest religion. This is not but a fabrication.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Has the message been revealed to him out of [all of] us?" Rather, they are in doubt about My message. Rather, they have not yet tasted My punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do they have the depositories of the mercy of your Lord, the Exalted in Might, the Bestower?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or is theirs the dominion of the heavens and the earth and what is between them? Then let them ascend through [any] ways of access.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They are but] soldiers [who will be] defeated there among the companies [of disbelievers].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The people of Noah denied before them, and [the tribe of] ''Aad and Pharaoh, the owner of stakes,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [the tribe of] Thamud and the people of Lot and the companions of the thicket. Those are the companies.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Each of them denied the messengers, so My penalty was justified.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And these [disbelievers] await not but one blast [of the Horn]; for it there will be no delay.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "Our Lord, hasten for us our share [of the punishment] before the Day of Account"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Be patient over what they say and remember Our servant, David, the possessor of strength; indeed, he was one who repeatedly turned back [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We subjected the mountains [to praise] with him, exalting [Allah] in the [late] afternoon and [after] sunrise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the birds were assembled, all with him repeating [praises].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We strengthened his kingdom and gave him wisdom and discernment in speech.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And has there come to you the news of the adversaries, when they climbed over the wall of [his] prayer chamber -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When they entered upon David and he was alarmed by them? They said, "Fear not. [We are] two adversaries, one of whom has wronged the other, so judge between us with truth and do not exceed [it] and guide us to the sound path.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed this, my brother, has ninety-nine ewes, and I have one ewe; so he said, ''Entrust her to me,'' and he overpowered me in speech."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[David] said, "He has certainly wronged you in demanding your ewe [in addition] to his ewes. And indeed, many associates oppress one another, except for those who believe and do righteous deeds - and few are they." And David became certain that We had tried him, and he asked forgiveness of his Lord and fell down bowing [in prostration] and turned in repentance [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So We forgave him that; and indeed, for him is nearness to Us and a good place of return.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[We said], "O David, indeed We have made you a successor upon the earth, so judge between the people in truth and do not follow [your own] desire, as it will lead you astray from the way of Allah." Indeed, those who go astray from the way of Allah will have a severe punishment for having forgotten the Day of Account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not create the heaven and the earth and that between them aimlessly. That is the assumption of those who disbelieve, so woe to those who disbelieve from the Fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or should we treat those who believe and do righteous deeds like corrupters in the land? Or should We treat those who fear Allah like the wicked?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[This is] a blessed Book which We have revealed to you, [O Muhammad], that they might reflect upon its verses and that those of understanding would be reminded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to David We gave Solomon. An excellent servant, indeed he was one repeatedly turning back [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Mention] when there were exhibited before him in the afternoon the poised [standing] racehorses.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he said, "Indeed, I gave preference to the love of good [things] over the remembrance of my Lord until the sun disappeared into the curtain [of darkness]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He said], "Return them to me," and set about striking [their] legs and necks.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We certainly tried Solomon and placed on his throne a body; then he returned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "My Lord, forgive me and grant me a kingdom such as will not belong to anyone after me. Indeed, You are the Bestower."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So We subjected to him the wind blowing by his command, gently, wherever he directed,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [also] the devils [of jinn] - every builder and diver', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And others bound together in shackles.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[We said], "This is Our gift, so grant or withhold without account."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, for him is nearness to Us and a good place of return.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And remember Our servant Job, when he called to his Lord, "Indeed, Satan has touched me with hardship and torment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[So he was told], "Strike [the ground] with your foot; this is a [spring for] a cool bath and drink."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We granted him his family and a like [number] with them as mercy from Us and a reminder for those of understanding.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[We said], "And take in your hand a bunch [of grass] and strike with it and do not break your oath." Indeed, We found him patient, an excellent servant. Indeed, he was one repeatedly turning back [to Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And remember Our servants, Abraham, Isaac and Jacob - those of strength and [religious] vision.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We chose them for an exclusive quality: remembrance of the home [of the Hereafter].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed they are, to Us, among the chosen and outstanding.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And remember Ishmael, Elisha and Dhul-Kifl, and all are among the outstanding.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This is a reminder. And indeed, for the righteous is a good place of return', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Gardens of perpetual residence, whose doors will be opened to them.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Reclining within them, they will call therein for abundant fruit and drink.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And with them will be women limiting [their] glances and of equal age.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This is what you, [the righteous], are promised for the Day of Account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, this is Our provision; for it there is no depletion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This [is so]. But indeed, for the transgressors is an evil place of return -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Hell, which they will [enter to] burn, and wretched is the resting place.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This - so let them taste it - is scalding water and [foul] purulence.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And other [punishments] of its type [in various] kinds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Its inhabitants will say], "This is a company bursting in with you. No welcome for them. Indeed, they will burn in the Fire."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "Nor you! No welcome for you. You, [our leaders], brought this upon us, and wretched is the settlement."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "Our Lord, whoever brought this upon us - increase for him double punishment in the Fire."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will say, "Why do we not see men whom we used to count among the worst?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is it [because] we took them in ridicule, or has [our] vision turned away from them?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, that is truth - the quarreling of the people of the Fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "I am only a warner, and there is not any deity except Allah, the One, the Prevailing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Lord of the heavens and the earth and whatever is between them, the Exalted in Might, the Perpetual Forgiver."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "It is great news', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'From which you turn away.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'I had no knowledge of the exalted assembly [of angels] when they were disputing [the creation of Adam].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It has not been revealed to me except that I am a clear warner."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[So mention] when your Lord said to the angels, "Indeed, I am going to create a human being from clay.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So when I have proportioned him and breathed into him of My [created] soul, then fall down to him in prostration."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So the angels prostrated - all of them entirely.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except Iblees; he was arrogant and became among the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "O Iblees, what prevented you from prostrating to that which I created with My hands? Were you arrogant [then], or were you [already] among the haughty?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "I am better than him. You created me from fire and created him from clay."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "Then get out of Paradise, for indeed, you are expelled.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, upon you is My curse until the Day of Recompense."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He said, "My Lord, then reprieve me until the Day they are resurrected."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "So indeed, you are of those reprieved', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Until the Day of the time well-known."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Iblees] said, "By your might, I will surely mislead them all', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except, among them, Your chosen servants."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah] said, "The truth [is My oath], and the truth I say -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[That] I will surely fill Hell with you and those of them that follow you all together."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "I do not ask you for the Qur''an any payment, and I am not of the pretentious', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is but a reminder to the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 38 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you will surely know [the truth of] its information after a time."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The revelation of the Qur''an is from Allah, the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have sent down to you the Book, [O Muhammad], in truth. So worship Allah, [being] sincere to Him in religion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Unquestionably, for Allah is the pure religion. And those who take protectors besides Him [say], "We only worship them that they may bring us nearer to Allah in position." Indeed, Allah will judge between them concerning that over which they differ. Indeed, Allah does not guide he who is a liar and [confirmed] disbeliever.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If Allah had intended to take a son, He could have chosen from what He creates whatever He willed. Exalted is He; He is Allah, the One, the Prevailing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He created the heavens and earth in truth. He wraps the night over the day and wraps the day over the night and has subjected the sun and the moon, each running [its course] for a specified term. Unquestionably, He is the Exalted in Might, the Perpetual Forgiver.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He created you from one soul. Then He made from it its mate, and He produced for you from the grazing livestock eight mates. He creates you in the wombs of your mothers, creation after creation, within three darknesses. That is Allah, your Lord; to Him belongs dominion. There is no deity except Him, so how are you averted?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If you disbelieve - indeed, Allah is Free from need of you. And He does not approve for His servants disbelief. And if you are grateful, He approves it for you; and no bearer of burdens will bear the burden of another. Then to your Lord is your return, and He will inform you about what you used to do. Indeed, He is Knowing of that within the breasts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when adversity touches man, he calls upon his Lord, turning to Him [alone]; then when He bestows on him a favor from Himself, he forgets Him whom he called upon before, and he attributes to Allah equals to mislead [people] from His way. Say, "Enjoy your disbelief for a little; indeed, you are of the companions of the Fire."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is one who is devoutly obedient during periods of the night, prostrating and standing [in prayer], fearing the Hereafter and hoping for the mercy of his Lord, [like one who does not]? Say, "Are those who know equal to those who do not know?" Only they will remember [who are] people of understanding.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "O My servants who have believed, fear your Lord. For those who do good in this world is good, and the earth of Allah is spacious. Indeed, the patient will be given their reward without account."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "Indeed, I have been commanded to worship Allah, [being] sincere to Him in religion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And I have been commanded to be the first [among you] of the Muslims."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Indeed I fear, if I should disobey my Lord, the punishment of a tremendous Day."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Allah [alone] do I worship, sincere to Him in my religion,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So worship what you will besides Him." Say, "Indeed, the losers are the ones who will lose themselves and their families on the Day of Resurrection. Unquestionably, that is the manifest loss."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will have canopies of fire above them and below them, canopies. By that Allah threatens His servants. O My servants, then fear Me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who have avoided Taghut, lest they worship it, and turned back to Allah - for them are good tidings. So give good tidings to My servants', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who listen to speech and follow the best of it. Those are the ones Allah has guided, and those are people of understanding.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, is one who has deserved the decree of punishment [to be guided]? Then, can you save one who is in the Fire?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who have feared their Lord - for them are chambers, above them chambers built high, beneath which rivers flow. [This is] the promise of Allah. Allah does not fail in [His] promise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you not see that Allah sends down rain from the sky and makes it flow as springs [and rivers] in the earth; then He produces thereby crops of varying colors; then they dry and you see them turned yellow; then He makes them [scattered] debris. Indeed in that is a reminder for those of understanding.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So is one whose breast Allah has expanded to [accept] Islam and he is upon a light from his Lord [like one whose heart rejects it]? Then woe to those whose hearts are hardened against the remembrance of Allah. Those are in manifest error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah has sent down the best statement: a consistent Book wherein is reiteration. The skins shiver therefrom of those who fear their Lord; then their skins and their hearts relax at the remembrance of Allah. That is the guidance of Allah by which He guides whom He wills. And one whom Allah leaves astray - for him there is no guide.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then is he who will shield with his face the worst of the punishment on the Day of Resurrection [like one secure from it]? And it will be said to the wrongdoers, "Taste what you used to earn."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those before them denied, and punishment came upon them from where they did not perceive.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So Allah made them taste disgrace in worldly life. But the punishment of the Hereafter is greater, if they only knew.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have certainly presented for the people in this Qur''an from every [kind of] example - that they might remember.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It is] an Arabic Qur''an, without any deviance that they might become righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah presents an example: a slave owned by quarreling partners and another belonging exclusively to one man - are they equal in comparison? Praise be to Allah! But most of them do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, you are to die, and indeed, they are to die.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then indeed you, on the Day of Resurrection, before your Lord, will dispute.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So who is more unjust than one who lies about Allah and denies the truth when it has come to him? Is there not in Hell a residence for the disbelievers?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the one who has brought the truth and [they who] believed in it - those are the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will have whatever they desire with their Lord. That is the reward of the doers of good -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That Allah may remove from them the worst of what they did and reward them their due for the best of what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is not Allah sufficient for His Servant [Prophet Muhammad]? And [yet], they threaten you with those [they worship] other than Him. And whoever Allah leaves astray - for him there is no guide.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever Allah guides - for him there is no misleader. Is not Allah Exalted in Might and Owner of Retribution?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you asked them, "Who created the heavens and the earth?" they would surely say, "Allah." Say, "Then have you considered what you invoke besides Allah? If Allah intended me harm, are they removers of His harm; or if He intended me mercy, are they withholders of His mercy?" Say, "Sufficient for me is Allah; upon Him [alone] rely the [wise] reliers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "O my people, work according to your position, [for] indeed, I am working; and you are going to know', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To whom will come a torment disgracing him and on whom will descend an enduring punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We sent down to you the Book for the people in truth. So whoever is guided - it is for [the benefit of] his soul; and whoever goes astray only goes astray to its detriment. And you are not a manager over them.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah takes the souls at the time of their death, and those that do not die [He takes] during their sleep. Then He keeps those for which He has decreed death and releases the others for a specified term. Indeed in that are signs for a people who give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or have they taken other than Allah as intercessors? Say, "Even though they do not possess [power over] anything, nor do they reason?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "To Allah belongs [the right to allow] intercession entirely. To Him belongs the dominion of the heavens and the earth. Then to Him you will be returned."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Allah is mentioned alone, the hearts of those who do not believe in the Hereafter shrink with aversion, but when those [worshipped] other than Him are mentioned, immediately they rejoice.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "O Allah, Creator of the heavens and the earth, Knower of the unseen and the witnessed, You will judge between your servants concerning that over which they used to differ."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if those who did wrong had all that is in the earth entirely and the like of it with it, they would [attempt to] ransom themselves thereby from the worst of the punishment on the Day of Resurrection. And there will appear to them from Allah that which they had not taken into account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there will appear to them the evils they had earned, and they will be enveloped by what they used to ridicule.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when adversity touches man, he calls upon Us; then when We bestow on him a favor from Us, he says, "I have only been given it because of [my] knowledge." Rather, it is a trial, but most of them do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those before them had already said it, but they were not availed by what they used to earn.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the evil consequences of what they earned struck them. And those who have wronged of these [people] will be afflicted by the evil consequences of what they earned; and they will not cause failure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they not know that Allah extends provision for whom He wills and restricts [it]? Indeed in that are signs for a people who believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "O My servants who have transgressed against themselves [by sinning], do not despair of the mercy of Allah. Indeed, Allah forgives all sins. Indeed, it is He who is the Forgiving, the Merciful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And return [in repentance] to your Lord and submit to Him before the punishment comes upon you; then you will not be helped.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And follow the best of what was revealed to you from your Lord before the punishment comes upon you suddenly while you do not perceive,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Lest a soul should say, "Oh [how great is] my regret over what I neglected in regard to Allah and that I was among the mockers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or [lest] it say, "If only Allah had guided me, I would have been among the righteous."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or [lest] it say when it sees the punishment, "If only I had another turn so I could be among the doers of good."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But yes, there had come to you My verses, but you denied them and were arrogant, and you were among the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And on the Day of Resurrection you will see those who lied about Allah [with] their faces blackened. Is there not in Hell a residence for the arrogant?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah will save those who feared Him by their attainment; no evil will touch them, nor will they grieve.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah is the Creator of all things, and He is, over all things, Disposer of affairs.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Him belong the keys of the heavens and the earth. And they who disbelieve in the verses of Allah - it is those who are the losers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "Is it other than Allah that you order me to worship, O ignorant ones?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it was already revealed to you and to those before you that if you should associate [anything] with Allah, your work would surely become worthless, and you would surely be among the losers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, worship [only] Allah and be among the grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They have not appraised Allah with true appraisal, while the earth entirely will be [within] His grip on the Day of Resurrection, and the heavens will be folded in His right hand. Exalted is He and high above what they associate with Him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the Horn will be blown, and whoever is in the heavens and whoever is on the earth will fall dead except whom Allah wills. Then it will be blown again, and at once they will be standing, looking on.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the earth will shine with the light of its Lord, and the record [of deeds] will be placed, and the prophets and the witnesses will be brought, and it will be judged between them in truth, and they will not be wronged.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And every soul will be fully compensated [for] what it did; and He is most knowing of what they do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who disbelieved will be driven to Hell in groups until, when they reach it, its gates are opened and its keepers will say, "Did there not come to you messengers from yourselves, reciting to you the verses of your Lord and warning you of the meeting of this Day of yours?" They will say, "Yes, but the word of punishment has come into effect upon the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[To them] it will be said, "Enter the gates of Hell to abide eternally therein, and wretched is the residence of the arrogant."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But those who feared their Lord will be driven to Paradise in groups until, when they reach it while its gates have been opened and its keepers say, "Peace be upon you; you have become pure; so enter it to abide eternally therein," [they will enter].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will say, "Praise to Allah, who has fulfilled for us His promise and made us inherit the earth [so] we may settle in Paradise wherever we will. And excellent is the reward of [righteous] workers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 39 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you will see the angels surrounding the Throne, exalting [Allah] with praise of their Lord. And it will be judged between them in truth, and it will be said, "[All] praise to Allah, Lord of the worlds."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Ha, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The revelation of the Book is from Allah, the Exalted in Might, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The forgiver of sin, acceptor of repentance, severe in punishment, owner of abundance. There is no deity except Him; to Him is the destination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'No one disputes concerning the signs of Allah except those who disbelieve, so be not deceived by their [uninhibited] movement throughout the land.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The people of Noah denied before them and the [disbelieving] factions after them, and every nation intended [a plot] for their messenger to seize him, and they disputed by [using] falsehood to [attempt to] invalidate thereby the truth. So I seized them, and how [terrible] was My penalty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And thus has the word of your Lord come into effect upon those who disbelieved that they are companions of the Fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those [angels] who carry the Throne and those around it exalt [Allah] with praise of their Lord and believe in Him and ask forgiveness for those who have believed, [saying], "Our Lord, You have encompassed all things in mercy and knowledge, so forgive those who have repented and followed Your way and protect them from the punishment of Hellfire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Our Lord, and admit them to gardens of perpetual residence which You have promised them and whoever was righteous among their fathers, their spouses and their offspring. Indeed, it is You who is the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And protect them from the evil consequences [of their deeds]. And he whom You protect from evil consequences that Day - You will have given him mercy. And that is the great attainment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who disbelieve will be addressed, "The hatred of Allah for you was [even] greater than your hatred of yourselves [this Day in Hell] when you were invited to faith, but you refused."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "Our Lord, You made us lifeless twice and gave us life twice, and we have confessed our sins. So is there to an exit any way?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will be told], "That is because, when Allah was called upon alone, you disbelieved; but if others were associated with Him, you believed. So the judgement is with Allah, the Most High, the Grand."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who shows you His signs and sends down to you from the sky, provision. But none will remember except he who turns back [in repentance].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So invoke Allah, [being] sincere to Him in religion, although the disbelievers dislike it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He is] the Exalted above [all] degrees, Owner of the Throne; He places the inspiration of His command upon whom He wills of His servants to warn of the Day of Meeting.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day they come forth nothing concerning them will be concealed from Allah. To whom belongs [all] sovereignty this Day? To Allah, the One, the Prevailing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This Day every soul will be recompensed for what it earned. No injustice today! Indeed, Allah is swift in account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And warn them, [O Muhammad], of the Approaching Day, when hearts are at the throats, filled [with distress]. For the wrongdoers there will be no devoted friend and no intercessor [who is] obeyed.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He knows that which deceives the eyes and what the breasts conceal.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah judges with truth, while those they invoke besides Him judge not with anything. Indeed, Allah - He is the Hearing, the Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not traveled through the land and observed how was the end of those who were before them? They were greater than them in strength and in impression on the land, but Allah seized them for their sins. And they had not from Allah any protector.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That was because their messengers were coming to them with clear proofs, but they disbelieved, so Allah seized them. Indeed, He is Powerful and severe in punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did certainly send Moses with Our signs and a clear authority', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Pharaoh, Haman and Qarun; but they said, "[He is] a magician and a liar."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when he brought them the truth from Us, they said, "Kill the sons of those who have believed with him and keep their women alive." But the plan of the disbelievers is not except in error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Pharaoh said, "Let me kill Moses and let him call upon his Lord. Indeed, I fear that he will change your religion or that he will cause corruption in the land."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But Moses said, "Indeed, I have sought refuge in my Lord and your Lord from every arrogant one who does not believe in the Day of Account."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And a believing man from the family of Pharaoh who concealed his faith said, "Do you kill a man [merely] because he says, ''My Lord is Allah'' while he has brought you clear proofs from your Lord? And if he should be lying, then upon him is [the consequence of] his lie; but if he should be truthful, there will strike you some of what he promises you. Indeed, Allah does not guide one who is a transgressor and a liar.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O my people, sovereignty is yours today, [your being] dominant in the land. But who would protect us from the punishment of Allah if it came to us?" Pharaoh said, "I do not show you except what I see, and I do not guide you except to the way of right conduct."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he who believed said, "O my people, indeed I fear for you [a fate] like the day of the companies -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Like the custom of the people of Noah and of ''Aad and Thamud and those after them. And Allah wants no injustice for [His] servants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, indeed I fear for you the Day of Calling -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day you will turn your backs fleeing; there is not for you from Allah any protector. And whoever Allah leaves astray - there is not for him any guide.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Joseph had already come to you before with clear proofs, but you remained in doubt of that which he brought to you, until when he died, you said, ''Never will Allah send a messenger after him.'' Thus does Allah leave astray he who is a transgressor and skeptic."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who dispute concerning the signs of Allah without an authority having come to them - great is hatred [of them] in the sight of Allah and in the sight of those who have believed. Thus does Allah seal over every heart [belonging to] an arrogant tyrant.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Pharaoh said, "O Haman, construct for me a tower that I might reach the ways -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The ways into the heavens - so that I may look at the deity of Moses; but indeed, I think he is a liar." And thus was made attractive to Pharaoh the evil of his deed, and he was averted from the [right] way. And the plan of Pharaoh was not except in ruin.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he who believed said, "O my people, follow me, I will guide you to the way of right conduct.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'O my people, this worldly life is only [temporary] enjoyment, and indeed, the Hereafter - that is the home of [permanent] settlement.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever does an evil deed will not be recompensed except by the like thereof; but whoever does righteousness, whether male or female, while he is a believer - those will enter Paradise, being given provision therein without account.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And O my people, how is it that I invite you to salvation while you invite me to the Fire?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You invite me to disbelieve in Allah and associate with Him that of which I have no knowledge, and I invite you to the Exalted in Might, the Perpetual Forgiver.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Assuredly, that to which you invite me has no [response to a] supplication in this world or in the Hereafter; and indeed, our return is to Allah, and indeed, the transgressors will be companions of the Fire.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you will remember what I [now] say to you, and I entrust my affair to Allah. Indeed, Allah is Seeing of [His] servants."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So Allah protected him from the evils they plotted, and the people of Pharaoh were enveloped by the worst of punishment -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Fire, they are exposed to it morning and evening. And the Day the Hour appears [it will be said], "Make the people of Pharaoh enter the severest punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention] when they will argue within the Fire, and the weak will say to those who had been arrogant, "Indeed, we were [only] your followers, so will you relieve us of a share of the Fire?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who had been arrogant will say, "Indeed, all [of us] are in it. Indeed, Allah has judged between the servants."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those in the Fire will say to the keepers of Hell, "Supplicate your Lord to lighten for us a day from the punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will say, "Did there not come to you your messengers with clear proofs?" They will say, "Yes." They will reply, "Then supplicate [yourselves], but the supplication of the disbelievers is not except in error."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We will support Our messengers and those who believe during the life of this world and on the Day when the witnesses will stand -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day their excuse will not benefit the wrongdoers, and they will have the curse, and they will have the worst home.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had certainly given Moses guidance, and We caused the Children of Israel to inherit the Scripture', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As guidance and a reminder for those of understanding.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So be patient, [O Muhammad]. Indeed, the promise of Allah is truth. And ask forgiveness for your sin and exalt [Allah] with praise of your Lord in the evening and the morning.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who dispute concerning the signs of Allah without [any] authority having come to them - there is not within their breasts except pride, [the extent of] which they cannot reach. So seek refuge in Allah. Indeed, it is He who is the Hearing, the Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The creation of the heavens and earth is greater than the creation of mankind, but most of the people do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And not equal are the blind and the seeing, nor are those who believe and do righteous deeds and the evildoer. Little do you remember.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the Hour is coming - no doubt about it - but most of the people do not believe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And your Lord says, "Call upon Me; I will respond to you." Indeed, those who disdain My worship will enter Hell [rendered] contemptible.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who made for you the night that you may rest therein and the day giving sight. Indeed, Allah is full of bounty to the people, but most of the people are not grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is Allah, your Lord, Creator of all things; there is no deity except Him, so how are you deluded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thus were those [before you] deluded who were rejecting the signs of Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who made for you the earth a place of settlement and the sky a ceiling and formed you and perfected your forms and provided you with good things. That is Allah, your Lord; then blessed is Allah, Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He is the Ever-Living; there is no deity except Him, so call upon Him, [being] sincere to Him in religion. [All] praise is [due] to Allah, Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "Indeed, I have been forbidden to worship those you call upon besides Allah once the clear proofs have come to me from my Lord, and I have been commanded to submit to the Lord of the worlds."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is He who created you from dust, then from a sperm-drop, then from a clinging clot; then He brings you out as a child; then [He develops you] that you reach your [time of] maturity, then [further] that you become elders. And among you is he who is taken in death before [that], so that you reach a specified term; and perhaps you will use reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He it is who gives life and causes death; and when He decrees a matter, He but says to it, "Be," and it is.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do you not consider those who dispute concerning the signs of Allah - how are they averted?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who deny the Book and that with which We sent Our messengers - they are going to know,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'When the shackles are around their necks and the chains; they will be dragged', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'In boiling water; then in the Fire they will be filled [with flame].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then it will be said to them, "Where is that which you used to associate [with Him in worship]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Other than Allah?" They will say, "They have departed from us; rather, we did not used to invoke previously anything." Thus does Allah put astray the disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The angels will say], "That was because you used to exult upon the earth without right and you used to behave insolently.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Enter the gates of Hell to abide eternally therein, and wretched is the residence of the arrogant."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So be patient, [O Muhammad]; indeed, the promise of Allah is truth. And whether We show you some of what We have promised them or We take you in death, it is to Us they will be returned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We have already sent messengers before you. Among them are those [whose stories] We have related to you, and among them are those [whose stories] We have not related to you. And it was not for any messenger to bring a sign [or verse] except by permission of Allah. So when the command of Allah comes, it will be concluded in truth, and the falsifiers will thereupon lose [all].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who made for you the grazing animals upon which you ride, and some of them you eat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And for you therein are [other] benefits and that you may realize upon them a need which is in your breasts; and upon them and upon ships you are carried.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He shows you His signs. So which of the signs of Allah do you deny?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have they not traveled through the land and observed how was the end of those before them? They were more numerous than themselves and greater in strength and in impression on the land, but they were not availed by what they used to earn.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when their messengers came to them with clear proofs, they [merely] rejoiced in what they had of knowledge, but they were enveloped by what they used to ridicule.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they saw Our punishment, they said," We believe in Allah alone and disbelieve in that which we used to associate with Him."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 40 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But never did their faith benefit them once they saw Our punishment. [It is] the established way of Allah which has preceded among His servants. And the disbelievers thereupon lost [all].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Ha, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[This is] a revelation from the Entirely Merciful, the Especially Merciful -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'A Book whose verses have been detailed, an Arabic Qur''an for a people who know,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As a giver of good tidings and a warner; but most of them turn away, so they do not hear.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "Our hearts are within coverings from that to which you invite us, and in our ears is deafness, and between us and you is a partition, so work; indeed, we are working."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, O [Muhammad], "I am only a man like you to whom it has been revealed that your god is but one God; so take a straight course to Him and seek His forgiveness." And woe to those who associate others with Allah -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who do not give zakah, and in the Hereafter they are disbelievers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who believe and do righteous deeds - for them is a reward uninterrupted.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Do you indeed disbelieve in He who created the earth in two days and attribute to Him equals? That is the Lord of the worlds."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He placed on the earth firmly set mountains over its surface, and He blessed it and determined therein its [creatures''] sustenance in four days without distinction - for [the information] of those who ask.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then He directed Himself to the heaven while it was smoke and said to it and to the earth, "Come [into being], willingly or by compulsion." They said, "We have come willingly."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He completed them as seven heavens within two days and inspired in each heaven its command. And We adorned the nearest heaven with lamps and as protection. That is the determination of the Exalted in Might, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if they turn away, then say, "I have warned you of a thunderbolt like the thunderbolt [that struck] ''Aad and Thamud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[That occurred] when the messengers had come to them before them and after them, [saying], "Worship not except Allah." They said, "If our Lord had willed, He would have sent down the angels, so indeed we, in that with which you have been sent, are disbelievers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As for ''Aad, they were arrogant upon the earth without right and said, "Who is greater than us in strength?" Did they not consider that Allah who created them was greater than them in strength? But they were rejecting Our signs.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So We sent upon them a screaming wind during days of misfortune to make them taste the punishment of disgrace in the worldly life; but the punishment of the Hereafter is more disgracing, and they will not be helped.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And as for Thamud, We guided them, but they preferred blindness over guidance, so the thunderbolt of humiliating punishment seized them for what they used to earn.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We saved those who believed and used to fear Allah.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention, O Muhammad], the Day when the enemies of Allah will be gathered to the Fire while they are [driven] assembled in rows,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Until, when they reach it, their hearing and their eyes and their skins will testify against them of what they used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will say to their skins, "Why have you testified against us?" They will say, "We were made to speak by Allah, who has made everything speak; and He created you the first time, and to Him you are returned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you were not covering yourselves, lest your hearing testify against you or your sight or your skins, but you assumed that Allah does not know much of what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that was your assumption which you assumed about your Lord. It has brought you to ruin, and you have become among the losers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So [even] if they are patient, the Fire is a residence for them; and if they ask to appease [Allah], they will not be of those who are allowed to appease.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We appointed for them companions who made attractive to them what was before them and what was behind them [of sin], and the word has come into effect upon them among nations which had passed on before them of jinn and men. Indeed, they [all] were losers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who disbelieve say, "Do not listen to this Qur''an and speak noisily during [the recitation of] it that perhaps you will overcome."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But We will surely cause those who disbelieve to taste a severe punishment, and We will surely recompense them for the worst of what they had been doing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is the recompense of the enemies of Allah - the Fire. For them therein is the home of eternity as recompense for what they, of Our verses, were rejecting.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who disbelieved will [then] say, "Our Lord, show us those who misled us of the jinn and men [so] we may put them under our feet that they will be among the lowest."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who have said, "Our Lord is Allah " and then remained on a right course - the angels will descend upon them, [saying], "Do not fear and do not grieve but receive good tidings of Paradise, which you were promised.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We [angels] were your allies in worldly life and [are so] in the Hereafter. And you will have therein whatever your souls desire, and you will have therein whatever you request [or wish]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As accommodation from a [Lord who is] Forgiving and Merciful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And who is better in speech than one who invites to Allah and does righteousness and says, "Indeed, I am of the Muslims."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And not equal are the good deed and the bad. Repel [evil] by that [deed] which is better; and thereupon the one whom between you and him is enmity [will become] as though he was a devoted friend.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But none is granted it except those who are patient, and none is granted it except one having a great portion [of good].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if there comes to you from Satan an evil suggestion, then seek refuge in Allah. Indeed, He is the Hearing, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs are the night and day and the sun and moon. Do not prostrate to the sun or to the moon, but prostate to Allah, who created them, if it should be Him that you worship.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if they are arrogant - then those who are near your Lord exalt Him by night and by day, and they do not become weary.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs is that you see the earth stilled, but when We send down upon it rain, it quivers and grows. Indeed, He who has given it life is the Giver of Life to the dead. Indeed, He is over all things competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who inject deviation into Our verses are not concealed from Us. So, is he who is cast into the Fire better or he who comes secure on the Day of Resurrection? Do whatever you will; indeed, He is Seeing of what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, those who disbelieve in the message after it has come to them... And indeed, it is a mighty Book.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Falsehood cannot approach it from before it or from behind it; [it is] a revelation from a [Lord who is] Wise and Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Nothing is said to you, [O Muhammad], except what was already said to the messengers before you. Indeed, your Lord is a possessor of forgiveness and a possessor of painful penalty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We had made it a non-Arabic Qur''an, they would have said, "Why are its verses not explained in detail [in our language]? Is it a foreign [recitation] and an Arab [messenger]?" Say, "It is, for those who believe, a guidance and cure." And those who do not believe - in their ears is deafness, and it is upon them blindness. Those are being called from a distant place.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had already given Moses the Scripture, but it came under disagreement. And if not for a word that preceded from your Lord, it would have been concluded between them. And indeed they are, concerning the Qur''an, in disquieting doubt.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever does righteousness - it is for his [own] soul; and whoever does evil [does so] against it. And your Lord is not ever unjust to [His] servants.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To him [alone] is attributed knowledge of the Hour. And fruits emerge not from their coverings nor does a female conceive or give birth except with His knowledge. And the Day He will call to them, "Where are My ''partners''?" they will say, "We announce to You that there is [no longer] among us any witness [to that]."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And lost from them will be those they were invoking before, and they will be certain that they have no place of escape.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Man is not weary of supplication for good [things], but if evil touches him, he is hopeless and despairing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We let him taste mercy from Us after an adversity which has touched him, he will surely say, "This is [due] to me, and I do not think the Hour will occur; and [even] if I should be returned to my Lord, indeed, for me there will be with Him the best." But We will surely inform those who disbelieved about what they did, and We will surely make them taste a massive punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when We bestow favor upon man, he turns away and distances himself; but when evil touches him, then he is full of extensive supplication.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Have you considered: if the Qur''an is from Allah and you disbelieved in it, who would be more astray than one who is in extreme dissension?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We will show them Our signs in the horizons and within themselves until it becomes clear to them that it is the truth. But is it not sufficient concerning your Lord that He is, over all things, a Witness?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 41 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Unquestionably, they are in doubt about the meeting with their Lord. Unquestionably He is, of all things, encompassing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Ha, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '''Ayn, Seen, Qaf.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thus has He revealed to you, [O Muhammad], and to those before you - Allah, the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Him belongs whatever is in the heavens and whatever is in the earth, and He is the Most High, the Most Great.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The heavens almost break from above them, and the angels exalt [Allah] with praise of their Lord and ask forgiveness for those on earth. Unquestionably, it is Allah who is the Forgiving, the Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who take as allies other than Him - Allah is [yet] Guardian over them; and you, [O Muhammad], are not over them a manager.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And thus We have revealed to you an Arabic Qur''an that you may warn the Mother of Cities [Makkah] and those around it and warn of the Day of Assembly, about which there is no doubt. A party will be in Paradise and a party in the Blaze.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if Allah willed, He could have made them [of] one religion, but He admits whom He wills into His mercy. And the wrongdoers have not any protector or helper.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or have they taken protectors [or allies] besides him? But Allah - He is the Protector, and He gives life to the dead, and He is over all things competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And in anything over which you disagree - its ruling is [to be referred] to Allah. [Say], "That is Allah, my Lord; upon Him I have relied, and to Him I turn back."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[He is] Creator of the heavens and the earth. He has made for you from yourselves, mates, and among the cattle, mates; He multiplies you thereby. There is nothing like unto Him, and He is the Hearing, the Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Him belong the keys of the heavens and the earth. He extends provision for whom He wills and restricts [it]. Indeed He is, of all things, Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'He has ordained for you of religion what He enjoined upon Noah and that which We have revealed to you, [O Muhammad], and what We enjoined upon Abraham and Moses and Jesus - to establish the religion and not be divided therein. Difficult for those who associate others with Allah is that to which you invite them. Allah chooses for Himself whom He wills and guides to Himself whoever turns back [to Him].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they did not become divided until after knowledge had come to them - out of jealous animosity between themselves. And if not for a word that preceded from your Lord [postponing the penalty] until a specified time, it would have been concluded between them. And indeed, those who were granted inheritance of the Scripture after them are, concerning it, in disquieting doubt.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So to that [religion of Allah] invite, [O Muhammad], and remain on a right course as you are commanded and do not follow their inclinations but say, "I have believed in what Allah has revealed of the Qur''an, and I have been commanded to do justice among you. Allah is our Lord and your Lord. For us are our deeds, and for you your deeds. There is no [need for] argument between us and you. Allah will bring us together, and to Him is the [final] destination."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who argue concerning Allah after He has been responded to - their argument is invalid with their Lord, and upon them is [His] wrath, and for them is a severe punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who has sent down the Book in truth and [also] the balance. And what will make you perceive? Perhaps the Hour is near.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Those who do not believe in it are impatient for it, but those who believe are fearful of it and know that it is the truth. Unquestionably, those who dispute concerning the Hour are in extreme error.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Allah is Subtle with His servants; He gives provisions to whom He wills. And He is the Powerful, the Exalted in Might.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever desires the harvest of the Hereafter - We increase for him in his harvest. And whoever desires the harvest of this world - We give him thereof, but there is not for him in the Hereafter any share.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or have they other deities who have ordained for them a religion to which Allah has not consented? But if not for the decisive word, it would have been concluded between them. And indeed, the wrongdoers will have a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'You will see the wrongdoers fearful of what they have earned, and it will [certainly] befall them. And those who have believed and done righteous deeds will be in lush regions of the gardens [in Paradise] having whatever they will in the presence of their Lord. That is what is the great bounty.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is that of which Allah gives good tidings to His servants who believe and do righteous deeds. Say, [O Muhammad], "I do not ask you for this message any payment [but] only good will through kinship." And whoever commits a good deed - We will increase for him good therein. Indeed, Allah is Forgiving and Appreciative.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do they say, "He has invented about Allah a lie"? But if Allah willed, He could seal over your heart. And Allah eliminates falsehood and establishes the truth by His words. Indeed, He is Knowing of that within the breasts.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is He who accepts repentance from his servants and pardons misdeeds, and He knows what you do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He answers [the supplication of] those who have believed and done righteous deeds and increases [for] them from His bounty. But the disbelievers will have a severe punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if Allah had extended [excessively] provision for His servants, they would have committed tyranny throughout the earth. But He sends [it] down in an amount which He wills. Indeed He is, of His servants, Acquainted and Seeing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is He who sends down the rain after they had despaired and spreads His mercy. And He is the Protector, the Praiseworthy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of his signs is the creation of the heavens and earth and what He has dispersed throughout them of creatures. And He, for gathering them when He wills, is competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whatever strikes you of disaster - it is for what your hands have earned; but He pardons much.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you will not cause failure [to Allah] upon the earth. And you have not besides Allah any protector or helper.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And of His signs are the ships in the sea, like mountains.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'If He willed, He could still the wind, and they would remain motionless on its surface. Indeed in that are signs for everyone patient and grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or He could destroy them for what they earned; but He pardons much.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [that is so] those who dispute concerning Our signs may know that for them there is no place of escape.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So whatever thing you have been given - it is but [for] enjoyment of the worldly life. But what is with Allah is better and more lasting for those who have believed and upon their Lord rely', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who avoid the major sins and immoralities, and when they are angry, they forgive,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who have responded to their lord and established prayer and whose affair is [determined by] consultation among themselves, and from what We have provided them, they spend.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those who, when tyranny strikes them, they defend themselves,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the retribution for an evil act is an evil one like it, but whoever pardons and makes reconciliation - his reward is [due] from Allah. Indeed, He does not like wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever avenges himself after having been wronged - those have not upon them any cause [for blame].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The cause is only against the ones who wrong the people and tyrannize upon the earth without right. Those will have a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever is patient and forgives - indeed, that is of the matters [requiring] determination.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he whom Allah sends astray - for him there is no protector beyond Him. And you will see the wrongdoers, when they see the punishment, saying, "Is there for return [to the former world] any way?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you will see them being exposed to the Fire, humbled from humiliation, looking from [behind] a covert glance. And those who had believed will say, "Indeed, the [true] losers are the ones who lost themselves and their families on the Day of Resurrection. Unquestionably, the wrongdoers are in an enduring punishment."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And there will not be for them any allies to aid them other than Allah. And whoever Allah sends astray - for him there is no way.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Respond to your Lord before a Day comes from Allah of which there is no repelling. No refuge will you have that day, nor for you will there be any denial.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if they turn away - then We have not sent you, [O Muhammad], over them as a guardian; upon you is only [the duty of] notification. And indeed, when We let man taste mercy from us, he rejoices in it; but if evil afflicts him for what his hands have put forth, then indeed, man is ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'To Allah belongs the dominion of the heavens and the earth; He creates what he wills. He gives to whom He wills female [children], and He gives to whom He wills males.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or He makes them [both] males and females, and He renders whom He wills barren. Indeed, He is Knowing and Competent.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is not for any human being that Allah should speak to him except by revelation or from behind a partition or that He sends a messenger to reveal, by His permission, what He wills. Indeed, He is Most High and Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And thus We have revealed to you an inspiration of Our command. You did not know what is the Book or [what is] faith, but We have made it a light by which We guide whom We will of Our servants. And indeed, [O Muhammad], you guide to a straight path -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 42 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The path of Allah, to whom belongs whatever is in the heavens and whatever is on the earth. Unquestionably, to Allah do [all] matters evolve.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Ha, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By the clear Book,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We have made it an Arabic Qur''an that you might understand.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed it is, in the Mother of the Book with Us, exalted and full of wisdom.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then should We turn the message away, disregarding you, because you are a transgressing people?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And how many a prophet We sent among the former peoples,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But there would not come to them a prophet except that they used to ridicule him.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We destroyed greater than them in [striking] power, and the example of the former peoples has preceded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you should ask them, "Who has created the heavens and the earth?" they would surely say, "They were created by the Exalted in Might, the Knowing."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[The one] who has made for you the earth a bed and made for you upon it roads that you might be guided', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And who sends down rain from the sky in measured amounts, and We revive thereby a dead land - thus will you be brought forth -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And who created the species, all of them, and has made for you of ships and animals those which you mount.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That you may settle yourselves upon their backs and then remember the favor of your Lord when you have settled upon them and say. "Exalted is He who has subjected this to us, and we could not have [otherwise] subdued it.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed we, to our Lord, will [surely] return."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they have attributed to Him from His servants a portion. Indeed, man is clearly ungrateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or has He taken, out of what He has created, daughters and chosen you for [having] sons?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when one of them is given good tidings of that which he attributes to the Most Merciful in comparison, his face becomes dark, and he suppresses grief.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So is one brought up in ornaments while being during conflict unevident [attributed to Allah]?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they have made the angels, who are servants of the Most Merciful, females. Did they witness their creation? Their testimony will be recorded, and they will be questioned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they said, "If the Most Merciful had willed, we would not have worshipped them." They have of that no knowledge. They are not but falsifying.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or have We given them a book before the Qur''an to which they are adhering?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Rather, they say, "Indeed, we found our fathers upon a religion, and we are in their footsteps [rightly] guided."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And similarly, We did not send before you any warner into a city except that its affluent said, "Indeed, we found our fathers upon a religion, and we are, in their footsteps, following."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Each warner] said, "Even if I brought you better guidance than that [religion] upon which you found your fathers?" They said, "Indeed we, in that with which you were sent, are disbelievers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So we took retribution from them; then see how was the end of the deniers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [mention, O Muhammad], when Abraham said to his father and his people, "Indeed, I am disassociated from that which you worship', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except for He who created me; and indeed, He will guide me."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And he made it a word remaining among his descendants that they might return [to it].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'However, I gave enjoyment to these [people of Makkah] and their fathers until there came to them the truth and a clear Messenger.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when the truth came to them, they said, "This is magic, and indeed we are, concerning it, disbelievers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they said, "Why was this Qur''an not sent down upon a great man from [one of] the two cities?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Do they distribute the mercy of your Lord? It is We who have apportioned among them their livelihood in the life of this world and have raised some of them above others in degrees [of rank] that they may make use of one another for service. But the mercy of your Lord is better than whatever they accumulate.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if it were not that the people would become one community [of disbelievers], We would have made for those who disbelieve in the Most Merciful - for their houses - ceilings and stairways of silver upon which to mount', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And for their houses - doors and couches [of silver] upon which to recline', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And gold ornament. But all that is not but the enjoyment of worldly life. And the Hereafter with your Lord is for the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whoever is blinded from remembrance of the Most Merciful - We appoint for him a devil, and he is to him a companion.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, the devils avert them from the way [of guidance] while they think that they are [rightly] guided', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Until, when he comes to Us [at Judgement], he says [to his companion], "Oh, I wish there was between me and you the distance between the east and west - how wretched a companion."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And never will it benefit you that Day, when you have wronged, that you are [all] sharing in the punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then will you make the deaf hear, [O Muhammad], or guide the blind or he who is in clear error?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And whether [or not] We take you away [in death], indeed, We will take retribution upon them.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or whether [or not] We show you that which We have promised them, indeed, We are Perfect in Ability.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So adhere to that which is revealed to you. Indeed, you are on a straight path.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, it is a remembrance for you and your people, and you [all] are going to be questioned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And ask those We sent before you of Our messengers; have We made besides the Most Merciful deities to be worshipped?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And certainly did We send Moses with Our signs to Pharaoh and his establishment, and he said, "Indeed, I am the messenger of the Lord of the worlds."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when he brought them Our signs, at once they laughed at them.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We showed them not a sign except that it was greater than its sister, and We seized them with affliction that perhaps they might return [to faith].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they said [to Moses], "O magician, invoke for us your Lord by what He has promised you. Indeed, we will be guided."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But when We removed from them the affliction, at once they broke their word.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Pharaoh called out among his people; he said, "O my people, does not the kingdom of Egypt belong to me, and these rivers flowing beneath me; then do you not see?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or am I [not] better than this one who is insignificant and hardly makes himself clear?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then why have there not been placed upon him bracelets of gold or come with him the angels in conjunction?"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So he bluffed his people, and they obeyed him. Indeed, they were [themselves] a people defiantly disobedient [of Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when they angered Us, We took retribution from them and drowned them all.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We made them a precedent and an example for the later peoples.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when the son of Mary was presented as an example, immediately your people laughed aloud.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they said, "Are your gods better, or is he?" They did not present the comparison except for [mere] argument. But, [in fact], they are a people prone to dispute.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Jesus was not but a servant upon whom We bestowed favor, and We made him an example for the Children of Israel.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 60), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if We willed, We could have made [instead] of you angels succeeding [one another] on the earth.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 61), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, Jesus will be [a sign for] knowledge of the Hour, so be not in doubt of it, and follow Me. This is a straight path.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 62), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And never let Satan avert you. Indeed, he is to you a clear enemy.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 63), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Jesus brought clear proofs, he said, "I have come to you with wisdom and to make clear to you some of that over which you differ, so fear Allah and obey me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 64), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, Allah is my Lord and your Lord, so worship Him. This is a straight path."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 65), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But the denominations from among them differed [and separated], so woe to those who have wronged from the punishment of a painful Day.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 66), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Are they waiting except for the Hour to come upon them suddenly while they perceive not?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 67), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Close friends, that Day, will be enemies to each other, except for the righteous', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 68), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[To whom Allah will say], "O My servants, no fear will there be concerning you this Day, nor will you grieve,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 69), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[You] who believed in Our verses and were Muslims.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 70), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Enter Paradise, you and your kinds, delighted."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 71), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Circulated among them will be plates and vessels of gold. And therein is whatever the souls desire and [what] delights the eyes, and you will abide therein eternally.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 72), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And that is Paradise which you are made to inherit for what you used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 73), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'For you therein is much fruit from which you will eat.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the criminals will be in the punishment of Hell, abiding eternally.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 75), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It will not be allowed to subside for them, and they, therein, are in despair.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not wrong them, but it was they who were the wrongdoers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they will call, "O Malik, let your Lord put an end to us!" He will say, "Indeed, you will remain."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 78), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We had certainly brought you the truth, but most of you, to the truth, were averse.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or have they devised [some] affair? But indeed, We are devising [a plan].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do they think that We hear not their secrets and their private conversations? Yes, [We do], and Our messengers are with them recording.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], "If the Most Merciful had a son, then I would be the first of [his] worshippers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 82), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Exalted is the Lord of the heavens and the earth, Lord of the Throne, above what they describe.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 83), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So leave them to converse vainly and amuse themselves until they meet their Day which they are promised.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 84), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it is Allah who is [the only] deity in the heaven, and on the earth [the only] deity. And He is the Wise, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 85), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And blessed is He to whom belongs the dominion of the heavens and the earth and whatever is between them and with whom is knowledge of the Hour and to whom you will be returned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And those they invoke besides Him do not possess [power of] intercession; but only those who testify to the truth [can benefit], and they know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 87), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And if you asked them who created them, they would surely say, "Allah." So how are they deluded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 88), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [Allah acknowledges] his saying, "O my Lord, indeed these are a people who do not believe."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 43 AND a.ayah_number = 89), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So turn aside from them and say, "Peace." But they are going to know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Ha, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'By the clear Book,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We sent it down during a blessed night. Indeed, We were to warn [mankind].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'On that night is made distinct every precise matter -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Every] matter [proceeding] from Us. Indeed, We were to send [a messenger]', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As mercy from your Lord. Indeed, He is the Hearing, the Knowing.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Lord of the heavens and the earth and that between them, if you would be certain.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'There is no deity except Him; He gives life and causes death. [He is] your Lord and the Lord of your first forefathers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But they are in doubt, amusing themselves.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then watch for the Day when the sky will bring a visible smoke.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Covering the people; this is a painful torment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[They will say], "Our Lord, remove from us the torment; indeed, we are believers."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'How will there be for them a reminder [at that time]? And there had come to them a clear Messenger.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then they turned away from him and said, "[He was] taught [and is] a madman."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, We will remove the torment for a little. Indeed, you [disbelievers] will return [to disbelief].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day We will strike with the greatest assault, indeed, We will take retribution.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We had already tried before them the people of Pharaoh, and there came to them a noble messenger,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Saying], "Render to me the servants of Allah. Indeed, I am to you a trustworthy messenger,"', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [saying], "Be not haughty with Allah. Indeed, I have come to you with clear authority.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, I have sought refuge in my Lord and your Lord, lest you stone me.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But if you do not believe me, then leave me alone."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [finally] he called to his Lord that these were a criminal people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[Allah said], "Then set out with My servants by night. Indeed, you are to be pursued.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And leave the sea in stillness. Indeed, they are an army to be drowned."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'How much they left behind of gardens and springs', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And crops and noble sites', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And comfort wherein they were amused.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thus. And We caused to inherit it another people.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the heaven and earth wept not for them, nor were they reprieved.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We certainly saved the Children of Israel from the humiliating torment -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'From Pharaoh. Indeed, he was a haughty one among the transgressors.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We certainly chose them by knowledge over [all] the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We gave them of signs that in which there was a clear trial.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, these [disbelievers] are saying,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '"There is not but our first death, and we will not be resurrected.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then bring [back] our forefathers, if you should be truthful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Are they better or the people of Tubba'' and those before them? We destroyed them, [for] indeed, they were criminals.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 38), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did not create the heavens and earth and that between them in play.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 39), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'We did not create them except in truth, but most of them do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 40), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the Day of Judgement is the appointed time for them all -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 41), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The Day when no relation will avail a relation at all, nor will they be helped -', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 42), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Except those [believers] on whom Allah has mercy. Indeed, He is the Exalted in Might, the Merciful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 43), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the tree of zaqqum', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 44), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Is food for the sinful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 45), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Like murky oil, it boils within bellies', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 46), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Like the boiling of scalding water.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 47), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It will be commanded], "Seize him and drag him into the midst of the Hellfire,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 48), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then pour over his head from the torment of scalding water."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 49), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', '[It will be said], "Taste! Indeed, you are the honored, the noble!', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 50), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, this is what you used to dispute."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 51), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, the righteous will be in a secure place;', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 52), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Within gardens and springs,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 53), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Wearing [garments of] fine silk and brocade, facing each other.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 54), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Thus. And We will marry them to fair women with large, [beautiful] eyes.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 55), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will call therein for every [kind of] fruit - safe and secure.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 56), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'They will not taste death therein except the first death, and He will have protected them from the punishment of Hellfire', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 57), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'As bounty from your Lord. That is what is the great attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 58), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And indeed, We have eased the Qur''an in your tongue that they might be reminded.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 44 AND a.ayah_number = 59), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So watch, [O Muhammad]; indeed, they are watching [for your end].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 1), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Ha, Meem.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 2), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'The revelation of the Book is from Allah, the Exalted in Might, the Wise.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 3), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, within the heavens and earth are signs for the believers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 4), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And in the creation of yourselves and what He disperses of moving creatures are signs for people who are certain [in faith].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 5), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And [in] the alternation of night and day and [in] what Allah sends down from the sky of provision and gives life thereby to the earth after its lifelessness and [in His] directing of the winds are signs for a people who reason.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 6), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'These are the verses of Allah which We recite to you in truth. Then in what statement after Allah and His verses will they believe?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 7), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Woe to every sinful liar', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 8), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Who hears the verses of Allah recited to him, then persists arrogantly as if he had not heard them. So give him tidings of a painful punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 9), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when he knows anything of Our verses, he takes them in ridicule. Those will have a humiliating punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 10), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Before them is Hell, and what they had earned will not avail them at all nor what they had taken besides Allah as allies. And they will have a great punishment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 11), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This [Qur''an] is guidance. And those who have disbelieved in the verses of their Lord will have a painful punishment of foul nature.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 12), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'It is Allah who subjected to you the sea so that ships may sail upon it by His command and that you may seek of His bounty; and perhaps you will be grateful.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 13), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And He has subjected to you whatever is in the heavens and whatever is on the earth - all from Him. Indeed in that are signs for a people who give thought.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 14), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, [O Muhammad], to those who have believed that they [should] forgive those who expect not the days of Allah so that He may recompense a people for what they used to earn.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 15), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Whoever does a good deed - it is for himself; and whoever does evil - it is against the self. Then to your Lord you will be returned.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 16), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We did certainly give the Children of Israel the Scripture and judgement and prophethood, and We provided them with good things and preferred them over the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 17), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And We gave them clear proofs of the matter [of religion]. And they did not differ except after knowledge had come to them - out of jealous animosity between themselves. Indeed, your Lord will judge between them on the Day of Resurrection concerning that over which they used to differ.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 18), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then We put you, [O Muhammad], on an ordained way concerning the matter [of religion]; so follow it and do not follow the inclinations of those who do not know.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 19), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Indeed, they will never avail you against Allah at all. And indeed, the wrongdoers are allies of one another; but Allah is the protector of the righteous.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 20), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This [Qur''an] is enlightenment for mankind and guidance and mercy for a people who are certain [in faith].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 21), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Or do those who commit evils think We will make them like those who have believed and done righteous deeds - [make them] equal in their life and their death? Evil is that which they judge.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 22), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And Allah created the heavens and earth in truth and so that every soul may be recompensed for what it has earned, and they will not be wronged.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 23), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Have you seen he who has taken as his god his [own] desire, and Allah has sent him astray due to knowledge and has set a seal upon his hearing and his heart and put over his vision a veil? So who will guide him after Allah? Then will you not be reminded?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 24), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And they say, "There is not but our worldly life; we die and live, and nothing destroys us except time." And they have of that no knowledge; they are only assuming.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 25), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when Our verses are recited to them as clear evidences, their argument is only that they say, "Bring [back] our forefathers, if you should be truthful."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 26), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Say, "Allah causes you to live, then causes you to die; then He will assemble you for the Day of Resurrection, about which there is no doubt, but most of the people do not know."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 27), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Allah belongs the dominion of the heavens and the earth. And the Day the Hour appears - that Day the falsifiers will lose.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 28), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And you will see every nation kneeling [from fear]. Every nation will be called to its record [and told], "Today you will be recompensed for what you used to do.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 29), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'This, Our record, speaks about you in truth. Indeed, We were having transcribed whatever you used to do."', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 30), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'So as for those who believed and did righteous deeds, their Lord will admit them into His mercy. That is what is the clear attainment.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 31), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'But as for those who disbelieved, [it will be said], "Were not Our verses recited to you, but you were arrogant and became a people of criminals?', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 32), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And when it was said, ''Indeed, the promise of Allah is truth and the Hour [is coming] - no doubt about it,'' you said, ''We know not what is the Hour. We assume only assumption, and we are not convinced.'' "', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 33), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And the evil consequences of what they did will appear to them, and they will be enveloped by what they used to ridicule.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 34), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And it will be said, "Today We will forget you as you forgot the meeting of this Day of yours, and your refuge is the Fire, and for you there are no helpers.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 35), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'That is because you took the verses of Allah in ridicule, and worldly life deluded you." So that Day they will not be removed from it, nor will they be asked to appease [Allah].', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 36), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'Then, to Allah belongs [all] praise - Lord of the heavens and Lord of the earth, Lord of the worlds.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 45 AND a.ayah_number = 37), (SELECT id FROM mst_language WHERE code = 'en'), 'Sahih International', 'And to Him belongs [all] grandeur within the heavens and the earth, and He is the Exalted in Might, the Wise.', NOW(), NOW());
